import{_ as i,o as a,c as t,ai as l}from"./chunks/framework.C4ntERNc.js";const _=JSON.parse('{"title":"Errors and Diagnostics","description":"","frontmatter":{"title":"Errors and Diagnostics","lang":"en-US","layout":"doc","outline":"deep"},"headers":[],"relativePath":"reference-manual/errors-diagnostics-warnings.md","filePath":"reference-manual/errors-diagnostics-warnings.md"}'),n={name:"reference-manual/errors-diagnostics-warnings.md"};function r(s,e,o,d,c,h){return a(),t("div",null,[...e[0]||(e[0]=[l('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /jz-hdl/reference-manual/errors-diagnostics-warnings.md for this page in Markdown format</div><h1 id="errors-and-diagnostics" tabindex="-1">Errors and Diagnostics <a class="header-anchor" href="#errors-and-diagnostics" aria-label="Permalink to “Errors and Diagnostics”">​</a></h1><h2 id="severity-levels" tabindex="-1">Severity Levels <a class="header-anchor" href="#severity-levels" aria-label="Permalink to “Severity Levels”">​</a></h2><p>Every diagnostic emitted by the JZ-HDL compiler has one of three severity levels:</p><table tabindex="0"><thead><tr><th>Severity</th><th>Meaning</th><th>Effect</th></tr></thead><tbody><tr><td><strong>ERROR</strong></td><td>The design violates a language rule and cannot be compiled.</td><td>Compilation stops. No output is produced.</td></tr><tr><td><strong>WARNING</strong></td><td>The design is legal but likely contains an unintended issue (unused declarations, missing DEFAULT clauses, etc.).</td><td>Compilation continues. The design may work, but you should investigate.</td></tr><tr><td><strong>INFO</strong></td><td>Advisory information about the design (e.g., runtime division-by-zero risk, blackbox overrides that cannot be validated).</td><td>Compilation continues. Informational only — no action required unless the note is relevant to your intent.</td></tr></tbody></table><h3 id="controlling-diagnostic-output" tabindex="-1">Controlling Diagnostic Output <a class="header-anchor" href="#controlling-diagnostic-output" aria-label="Permalink to “Controlling Diagnostic Output”">​</a></h3><table tabindex="0"><thead><tr><th>CLI Flag</th><th>Effect</th></tr></thead><tbody><tr><td><code>--info</code></td><td>Show INFO-level diagnostics in addition to errors and warnings. Without this flag, only errors and warnings are displayed.</td></tr><tr><td><code>--warn-as-error</code></td><td>Promote all warnings to errors. Useful for CI pipelines where you want zero tolerance for potential issues.</td></tr><tr><td><code>--Wno-group=NAME</code></td><td>Suppress all diagnostics in the named group. For example, <code>--Wno-group=GENERAL_WARNINGS</code> silences unused register warnings, dead code warnings, etc.</td></tr><tr><td><code>--color</code></td><td>Force colored output. Errors appear in red, warnings in yellow, and info in blue.</td></tr></tbody></table><h3 id="listing-all-rules" tabindex="-1">Listing All Rules <a class="header-anchor" href="#listing-all-rules" aria-label="Permalink to “Listing All Rules”">​</a></h3><p>Use <code>--lint-rules</code> to print every diagnostic rule ID, its severity, and a short description:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jz-hdl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> design.jz</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --lint-rules</span></span></code></pre></div><p>This is useful for discovering the exact rule ID to reference when suppressing diagnostics with <code>--Wno-group</code>, or when searching this page for details about a specific diagnostic.</p><h2 id="diagnostic-reference" tabindex="-1">Diagnostic Reference <a class="header-anchor" href="#diagnostic-reference" aria-label="Permalink to “Diagnostic Reference”">​</a></h2><p>The sections below list all diagnostic rules organized by category. Each entry shows the rule ID, severity, typical cause, and how to fix it.</p><h2 id="parse-lexical" tabindex="-1">Parse &amp; Lexical <a class="header-anchor" href="#parse-lexical" aria-label="Permalink to “Parse &amp; Lexical”">​</a></h2><h3 id="parse-comment-in-token-—-comment-appears-inside-a-token" tabindex="-1">PARSE.COMMENT_IN_TOKEN — Comment appears inside a token <a class="header-anchor" href="#parse-comment-in-token-—-comment-appears-inside-a-token" aria-label="Permalink to “PARSE.COMMENT_IN_TOKEN — Comment appears inside a token”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: <code>/*</code> or <code>//</code> started inside an identifier/number/operator token.</li><li>Fix: Move comment boundaries so they appear between tokens or on separate lines.</li></ul><h3 id="parse-comment-nested-block-—-nested-block-comment-detected" tabindex="-1">PARSE.COMMENT_NESTED_BLOCK — Nested block comment detected <a class="header-anchor" href="#parse-comment-nested-block-—-nested-block-comment-detected" aria-label="Permalink to “PARSE.COMMENT_NESTED_BLOCK — Nested block comment detected”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: <code>/* ... /* ... */ ... */</code> — nested block comments are not supported.</li><li>Fix: Remove inner <code>/*</code> or close the outer block before starting another; use line comments instead.</li></ul><h3 id="parse-directive-invalid-context-—-directive-used-in-invalid-location" tabindex="-1">PARSE.DIRECTIVE_INVALID_CONTEXT — Directive used in invalid location <a class="header-anchor" href="#parse-directive-invalid-context-—-directive-used-in-invalid-location" aria-label="Permalink to “PARSE.DIRECTIVE_INVALID_CONTEXT — Directive used in invalid location”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Structural directives (@project, @module, @import, @new, @blackbox, @endproj, @endmod, etc.) placed where not allowed.</li><li>Fix: Place directives only in permitted locations per the spec (e.g., @import only immediately inside @project).</li></ul><h3 id="lexical-id-syntax-invalid-—-identifier-invalid" tabindex="-1">LEXICAL.ID_SYNTAX_INVALID — Identifier invalid <a class="header-anchor" href="#lexical-id-syntax-invalid-—-identifier-invalid" aria-label="Permalink to “LEXICAL.ID_SYNTAX_INVALID — Identifier invalid”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Identifier violates regex (bad characters, starts with digit) or length &gt; 255.</li><li>Fix: Rename to valid identifier per rules: [A‑Za‑z_][A‑Za‑z0‑9_]{0,254} and not a single underscore.</li></ul><h3 id="lexical-id-single-underscore-—-illegal-use-of-single-underscore" tabindex="-1">LEXICAL.ID_SINGLE_UNDERSCORE — Illegal use of single underscore <a class="header-anchor" href="#lexical-id-single-underscore-—-illegal-use-of-single-underscore" aria-label="Permalink to “LEXICAL.ID_SINGLE_UNDERSCORE — Illegal use of single underscore”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: <code>_</code> used as regular identifier outside no‑connect context (allowed only in @top/@new port bindings).</li><li>Fix: Use a named identifier or <code>_</code> only in permitted instantiation/top-level no‑connect positions.</li></ul><h3 id="parse-keyword-as-identifier-—-reserved-keyword-used-as-identifier" tabindex="-1">PARSE.KEYWORD_AS_IDENTIFIER — Reserved keyword used as identifier <a class="header-anchor" href="#parse-keyword-as-identifier-—-reserved-keyword-used-as-identifier" aria-label="Permalink to “PARSE.KEYWORD_AS_IDENTIFIER — Reserved keyword used as identifier”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Using a reserved uppercase keyword as an identifier.</li><li>Fix: Rename; reserved keywords (IF, ELSE, CONST, IN, OUT, etc.) cannot be used as identifiers.</li></ul><h3 id="parse-if-cond-missing-parens-—-if-elif-condition-missing-parentheses" tabindex="-1">PARSE.IF_COND_MISSING_PARENS — IF/ELIF condition missing parentheses <a class="header-anchor" href="#parse-if-cond-missing-parens-—-if-elif-condition-missing-parentheses" aria-label="Permalink to “PARSE.IF_COND_MISSING_PARENS — IF/ELIF condition missing parentheses”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: <code>IF cond {</code> instead of <code>IF (cond) {</code>.</li><li>Fix: Parenthesize the condition.</li></ul><h3 id="parse-lit-decimal-has-xz-—-decimal-literal-contains-x-or-z" tabindex="-1">PARSE.LIT_DECIMAL_HAS_XZ — Decimal literal contains x or z <a class="header-anchor" href="#parse-lit-decimal-has-xz-—-decimal-literal-contains-x-or-z" aria-label="Permalink to “PARSE.LIT_DECIMAL_HAS_XZ — Decimal literal contains x or z”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Decimal literals do not support <code>x</code>/<code>z</code> digits (e.g., <code>8&#39;d10x</code>).</li><li>Fix: Use hex or binary base for x/z values.</li></ul><h3 id="parse-lit-invalid-digit-for-base-—-invalid-digit-for-literal-base" tabindex="-1">PARSE.LIT_INVALID_DIGIT_FOR_BASE — Invalid digit for literal base <a class="header-anchor" href="#parse-lit-invalid-digit-for-base-—-invalid-digit-for-literal-base" aria-label="Permalink to “PARSE.LIT_INVALID_DIGIT_FOR_BASE — Invalid digit for literal base”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Literal contains a digit not valid for its base (e.g., <code>8&#39;b102</code>).</li><li>Fix: Use valid digits for the base.</li></ul><h3 id="parse-instance-undefined-module-—-instantiation-references-non-existent-module" tabindex="-1">PARSE.INSTANCE_UNDEFINED_MODULE — Instantiation references non-existent module <a class="header-anchor" href="#parse-instance-undefined-module-—-instantiation-references-non-existent-module" aria-label="Permalink to “PARSE.INSTANCE_UNDEFINED_MODULE — Instantiation references non-existent module”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Ensure the module is defined or imported before use.</li></ul><hr><h2 id="literals-types-widths" tabindex="-1">Literals, Types &amp; Widths <a class="header-anchor" href="#literals-types-widths" aria-label="Permalink to “Literals, Types &amp; Widths”">​</a></h2><h3 id="literals-and-types-lit-unsized-—-unsized-literal-used" tabindex="-1">LITERALS_AND_TYPES.LIT_UNSIZED — Unsized literal used <a class="header-anchor" href="#literals-and-types-lit-unsized-—-unsized-literal-used" aria-label="Permalink to “LITERALS_AND_TYPES.LIT_UNSIZED — Unsized literal used”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Literal missing width (e.g., <code>&#39;hFF</code>).</li><li>Fix: Provide explicit width: <code>8&#39;hFF</code>.</li></ul><h3 id="literals-and-types-lit-overflow-—-literal-intrinsic-width-declared-width" tabindex="-1">LITERALS_AND_TYPES.LIT_OVERFLOW — Literal intrinsic width &gt; declared width <a class="header-anchor" href="#literals-and-types-lit-overflow-—-literal-intrinsic-width-declared-width" aria-label="Permalink to “LITERALS_AND_TYPES.LIT_OVERFLOW — Literal intrinsic width &gt; declared width”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Value requires more bits than declared.</li><li>Fix: Increase literal width or shorten the value so intrinsic width ≤ declared width.</li></ul><h3 id="literals-and-types-lit-underscore-at-edges-—-underscore-at-start-end-of-literal" tabindex="-1">LITERALS_AND_TYPES.LIT_UNDERSCORE_AT_EDGES — Underscore at start/end of literal <a class="header-anchor" href="#literals-and-types-lit-underscore-at-edges-—-underscore-at-start-end-of-literal" aria-label="Permalink to “LITERALS_AND_TYPES.LIT_UNDERSCORE_AT_EDGES — Underscore at start/end of literal”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Literal has leading or trailing <code>_</code>.</li><li>Fix: Remove underscores at edges.</li></ul><h3 id="literals-and-types-lit-undefined-const-width-—-undefined-const-used-as-width" tabindex="-1">LITERALS_AND_TYPES.LIT_UNDEFINED_CONST_WIDTH — Undefined CONST used as width <a class="header-anchor" href="#literals-and-types-lit-undefined-const-width-—-undefined-const-used-as-width" aria-label="Permalink to “LITERALS_AND_TYPES.LIT_UNDEFINED_CONST_WIDTH — Undefined CONST used as width”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Using a module CONST name in a literal width that does not exist.</li><li>Fix: Declare the CONST or use a numeric width; CONST scope is module-local.</li></ul><h3 id="widths-and-slicing-width-nonpositive-or-nonint-—-invalid-declared-width" tabindex="-1">WIDTHS_AND_SLICING.WIDTH_NONPOSITIVE_OR_NONINT — Invalid declared width <a class="header-anchor" href="#widths-and-slicing-width-nonpositive-or-nonint-—-invalid-declared-width" aria-label="Permalink to “WIDTHS_AND_SLICING.WIDTH_NONPOSITIVE_OR_NONINT — Invalid declared width”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Declared width &lt;= 0 or not integer.</li><li>Fix: Use positive integer or valid CONST resolving to positive integer.</li></ul><h3 id="widths-and-slicing-slice-msb-less-than-lsb-—-slice-msb-lsb" tabindex="-1">WIDTHS_AND_SLICING.SLICE_MSB_LESS_THAN_LSB — Slice MSB &lt; LSB <a class="header-anchor" href="#widths-and-slicing-slice-msb-less-than-lsb-—-slice-msb-lsb" aria-label="Permalink to “WIDTHS_AND_SLICING.SLICE_MSB_LESS_THAN_LSB — Slice MSB &lt; LSB”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: <code>signal[H:L]</code> where H &lt; L.</li><li>Fix: Reverse indices or correct indices so MSB ≥ LSB.</li></ul><h3 id="widths-and-slicing-slice-index-out-of-range-—-slice-index-out-of-bounds" tabindex="-1">WIDTHS_AND_SLICING.SLICE_INDEX_OUT_OF_RANGE — Slice index out of bounds <a class="header-anchor" href="#widths-and-slicing-slice-index-out-of-range-—-slice-index-out-of-bounds" aria-label="Permalink to “WIDTHS_AND_SLICING.SLICE_INDEX_OUT_OF_RANGE — Slice index out of bounds”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Index &lt; 0 or &gt;= signal width.</li><li>Fix: Use valid indices within [0, width−1].</li></ul><h3 id="operators-and-expressions-type-binop-width-mismatch-—-binary-op-operands-differ-widths" tabindex="-1">OPERATORS_AND_EXPRESSIONS.TYPE_BINOP_WIDTH_MISMATCH — Binary op operands differ widths <a class="header-anchor" href="#operators-and-expressions-type-binop-width-mismatch-—-binary-op-operands-differ-widths" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.TYPE_BINOP_WIDTH_MISMATCH — Binary op operands differ widths”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Operators requiring equal widths (e.g., <code>+</code>, <code>&amp;</code>, <code>==</code>) receive different widths.</li><li>Fix: Make operand widths equal via explicit extension (<code>=z</code>/<code>=s</code> context) or resize using concatenation or intrinsics.</li></ul><hr><h2 id="operators-expressions" tabindex="-1">Operators &amp; Expressions <a class="header-anchor" href="#operators-expressions" aria-label="Permalink to “Operators &amp; Expressions”">​</a></h2><h3 id="operators-and-expressions-unary-arith-missing-parens-—-unary-arithmetic-missing-parentheses" tabindex="-1">OPERATORS_AND_EXPRESSIONS.UNARY_ARITH_MISSING_PARENS — Unary arithmetic missing parentheses <a class="header-anchor" href="#operators-and-expressions-unary-arith-missing-parens-—-unary-arithmetic-missing-parentheses" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.UNARY_ARITH_MISSING_PARENS — Unary arithmetic missing parentheses”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Used <code>-flag</code> instead of <code>(-flag)</code>.</li><li>Fix: Parenthesize unary arithmetic: <code>(-flag)</code>.</li></ul><h3 id="operators-and-expressions-logical-width-not-1-—-used-on-multi-bit" tabindex="-1">OPERATORS_AND_EXPRESSIONS.LOGICAL_WIDTH_NOT_1 — <code>&amp;&amp;</code>/<code>||</code>/<code>!</code> used on multi-bit <a class="header-anchor" href="#operators-and-expressions-logical-width-not-1-—-used-on-multi-bit" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.LOGICAL_WIDTH_NOT_1 — &amp;&amp;/||/! used on multi-bit”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Logical operators require width‑1 operands.</li><li>Fix: Reduce to a single-bit condition (e.g., <code>(a != 0)</code>), or use bitwise operators.</li></ul><h3 id="operators-and-expressions-ternary-cond-width-not-1-—-ternary-condition-not-width‐1" tabindex="-1">OPERATORS_AND_EXPRESSIONS.TERNARY_COND_WIDTH_NOT_1 — Ternary condition not width‑1 <a class="header-anchor" href="#operators-and-expressions-ternary-cond-width-not-1-—-ternary-condition-not-width‐1" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.TERNARY_COND_WIDTH_NOT_1 — Ternary condition not width‑1”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Ensure the condition expression is width‑1.</li></ul><h3 id="operators-and-expressions-ternary-branch-width-mismatch-—-branches-widths-differ" tabindex="-1">OPERATORS_AND_EXPRESSIONS.TERNARY_BRANCH_WIDTH_MISMATCH — Branches widths differ <a class="header-anchor" href="#operators-and-expressions-ternary-branch-width-mismatch-—-branches-widths-differ" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.TERNARY_BRANCH_WIDTH_MISMATCH — Branches widths differ”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: true/false expressions have different widths.</li><li>Fix: Make branches equal width by extending or slicing.</li></ul><h3 id="operators-and-expressions-concat-empty-—-empty-concatenation-used" tabindex="-1">OPERATORS_AND_EXPRESSIONS.CONCAT_EMPTY — Empty concatenation <code>{}</code> used <a class="header-anchor" href="#operators-and-expressions-concat-empty-—-empty-concatenation-used" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.CONCAT_EMPTY — Empty concatenation {} used”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Remove empty concat or supply elements.</li></ul><h3 id="operators-and-expressions-div-const-zero-—-division-by-constant-zero" tabindex="-1">OPERATORS_AND_EXPRESSIONS.DIV_CONST_ZERO — Division by constant zero <a class="header-anchor" href="#operators-and-expressions-div-const-zero-—-division-by-constant-zero" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.DIV_CONST_ZERO — Division by constant zero”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: A compile-time divisor literal = 0.</li><li>Fix: Remove or guard division; use conditional checks.</li></ul><h3 id="operators-and-expressions-div-unguarded-runtime-zero-—-divisor-may-be-zero-at-runtime" tabindex="-1">OPERATORS_AND_EXPRESSIONS.DIV_UNGUARDED_RUNTIME_ZERO — Divisor may be zero at runtime <a class="header-anchor" href="#operators-and-expressions-div-unguarded-runtime-zero-—-divisor-may-be-zero-at-runtime" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.DIV_UNGUARDED_RUNTIME_ZERO — Divisor may be zero at runtime”">​</a></h3><ul><li>Severity: WARNING</li><li>Cause: A division or modulus with a non-constant divisor is not enclosed in an <code>IF (divisor != 0)</code> guard.</li><li>Fix: Add runtime guards: <code>IF (divisor != 0) ... ELSE ...</code>.</li></ul><h3 id="operators-and-expressions-special-driver-in-expression-—-gnd-vcc-in-expression" tabindex="-1">OPERATORS_AND_EXPRESSIONS.SPECIAL_DRIVER_IN_EXPRESSION — GND/VCC in expression <a class="header-anchor" href="#operators-and-expressions-special-driver-in-expression-—-gnd-vcc-in-expression" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.SPECIAL_DRIVER_IN_EXPRESSION — GND/VCC in expression”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: GND/VCC may not appear in arithmetic/logical expressions.</li><li>Fix: Use sized literals (<code>1&#39;b0</code>, <code>1&#39;b1</code>) instead.</li></ul><h3 id="operators-and-expressions-special-driver-in-concat-—-gnd-vcc-in-concatenation" tabindex="-1">OPERATORS_AND_EXPRESSIONS.SPECIAL_DRIVER_IN_CONCAT — GND/VCC in concatenation <a class="header-anchor" href="#operators-and-expressions-special-driver-in-concat-—-gnd-vcc-in-concatenation" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.SPECIAL_DRIVER_IN_CONCAT — GND/VCC in concatenation”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Use sized literals instead of GND/VCC in concatenations.</li></ul><h3 id="operators-and-expressions-special-driver-sliced-—-gnd-vcc-sliced-or-indexed" tabindex="-1">OPERATORS_AND_EXPRESSIONS.SPECIAL_DRIVER_SLICED — GND/VCC sliced or indexed <a class="header-anchor" href="#operators-and-expressions-special-driver-sliced-—-gnd-vcc-sliced-or-indexed" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.SPECIAL_DRIVER_SLICED — GND/VCC sliced or indexed”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: GND/VCC are whole-signal drivers; use sized literals if you need specific bits.</li></ul><h3 id="operators-and-expressions-special-driver-in-index-—-gnd-vcc-in-index-expression" tabindex="-1">OPERATORS_AND_EXPRESSIONS.SPECIAL_DRIVER_IN_INDEX — GND/VCC in index expression <a class="header-anchor" href="#operators-and-expressions-special-driver-in-index-—-gnd-vcc-in-index-expression" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.SPECIAL_DRIVER_IN_INDEX — GND/VCC in index expression”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Use integer literals for indices.</li></ul><h3 id="operators-and-expressions-sbit-set-width-not-1-—-sbit-set-argument-not-width-1" tabindex="-1">OPERATORS_AND_EXPRESSIONS.SBIT_SET_WIDTH_NOT_1 — sbit() set argument not width-1 <a class="header-anchor" href="#operators-and-expressions-sbit-set-width-not-1-—-sbit-set-argument-not-width-1" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.SBIT_SET_WIDTH_NOT_1 — sbit() set argument not width-1”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: The third argument to sbit() must be a 1-bit expression.</li></ul><h3 id="operators-and-expressions-gbit-index-out-of-range-—-gbit-index-out-of-range" tabindex="-1">OPERATORS_AND_EXPRESSIONS.GBIT_INDEX_OUT_OF_RANGE — gbit() index out of range <a class="header-anchor" href="#operators-and-expressions-gbit-index-out-of-range-—-gbit-index-out-of-range" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.GBIT_INDEX_OUT_OF_RANGE — gbit() index out of range”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Ensure index is within [0, width(source)-1].</li></ul><h3 id="operators-and-expressions-gslice-index-out-of-range-—-gslice-index-out-of-range" tabindex="-1">OPERATORS_AND_EXPRESSIONS.GSLICE_INDEX_OUT_OF_RANGE — gslice() index out of range <a class="header-anchor" href="#operators-and-expressions-gslice-index-out-of-range-—-gslice-index-out-of-range" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.GSLICE_INDEX_OUT_OF_RANGE — gslice() index out of range”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Ensure index + width &lt;= width(source).</li></ul><h3 id="operators-and-expressions-gslice-width-invalid-—-gslice-width-invalid" tabindex="-1">OPERATORS_AND_EXPRESSIONS.GSLICE_WIDTH_INVALID — gslice() width invalid <a class="header-anchor" href="#operators-and-expressions-gslice-width-invalid-—-gslice-width-invalid" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.GSLICE_WIDTH_INVALID — gslice() width invalid”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Width parameter must be a positive integer constant.</li></ul><h3 id="operators-and-expressions-sslice-index-out-of-range-—-sslice-index-out-of-range" tabindex="-1">OPERATORS_AND_EXPRESSIONS.SSLICE_INDEX_OUT_OF_RANGE — sslice() index out of range <a class="header-anchor" href="#operators-and-expressions-sslice-index-out-of-range-—-sslice-index-out-of-range" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.SSLICE_INDEX_OUT_OF_RANGE — sslice() index out of range”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Ensure index + width &lt;= width(source).</li></ul><h3 id="operators-and-expressions-sslice-width-invalid-—-sslice-width-invalid" tabindex="-1">OPERATORS_AND_EXPRESSIONS.SSLICE_WIDTH_INVALID — sslice() width invalid <a class="header-anchor" href="#operators-and-expressions-sslice-width-invalid-—-sslice-width-invalid" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.SSLICE_WIDTH_INVALID — sslice() width invalid”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Width parameter must be a positive integer constant.</li></ul><h3 id="operators-and-expressions-sslice-value-width-mismatch-—-sslice-value-width-mismatch" tabindex="-1">OPERATORS_AND_EXPRESSIONS.SSLICE_VALUE_WIDTH_MISMATCH — sslice() value width mismatch <a class="header-anchor" href="#operators-and-expressions-sslice-value-width-mismatch-—-sslice-value-width-mismatch" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.SSLICE_VALUE_WIDTH_MISMATCH — sslice() value width mismatch”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Value argument width must match the width parameter.</li></ul><h3 id="operators-and-expressions-oh2b-input-too-narrow-—-oh2b-source-too-narrow" tabindex="-1">OPERATORS_AND_EXPRESSIONS.OH2B_INPUT_TOO_NARROW — oh2b() source too narrow <a class="header-anchor" href="#operators-and-expressions-oh2b-input-too-narrow-—-oh2b-source-too-narrow" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.OH2B_INPUT_TOO_NARROW — oh2b() source too narrow”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: oh2b() source must be at least 2 bits wide.</li></ul><h3 id="operators-and-expressions-b2oh-width-invalid-—-b2oh-width-invalid" tabindex="-1">OPERATORS_AND_EXPRESSIONS.B2OH_WIDTH_INVALID — b2oh() width invalid <a class="header-anchor" href="#operators-and-expressions-b2oh-width-invalid-—-b2oh-width-invalid" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.B2OH_WIDTH_INVALID — b2oh() width invalid”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Width must be a positive constant &gt;= 2.</li></ul><h3 id="operators-and-expressions-prienc-input-too-narrow-—-prienc-source-too-narrow" tabindex="-1">OPERATORS_AND_EXPRESSIONS.PRIENC_INPUT_TOO_NARROW — prienc() source too narrow <a class="header-anchor" href="#operators-and-expressions-prienc-input-too-narrow-—-prienc-source-too-narrow" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.PRIENC_INPUT_TOO_NARROW — prienc() source too narrow”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: prienc() source must be at least 2 bits wide.</li></ul><h3 id="operators-and-expressions-bswap-width-not-byte-aligned-—-bswap-width-not-byte-aligned" tabindex="-1">OPERATORS_AND_EXPRESSIONS.BSWAP_WIDTH_NOT_BYTE_ALIGNED — bswap() width not byte-aligned <a class="header-anchor" href="#operators-and-expressions-bswap-width-not-byte-aligned-—-bswap-width-not-byte-aligned" aria-label="Permalink to “OPERATORS_AND_EXPRESSIONS.BSWAP_WIDTH_NOT_BYTE_ALIGNED — bswap() width not byte-aligned”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Source width must be a multiple of 8.</li></ul><hr><h2 id="identifiers-scope" tabindex="-1">Identifiers &amp; Scope <a class="header-anchor" href="#identifiers-scope" aria-label="Permalink to “Identifiers &amp; Scope”">​</a></h2><h3 id="identifiers-and-scope-id-dup-in-module-—-duplicate-identifier-in-module" tabindex="-1">IDENTIFIERS_AND_SCOPE.ID_DUP_IN_MODULE — Duplicate identifier in module <a class="header-anchor" href="#identifiers-and-scope-id-dup-in-module-—-duplicate-identifier-in-module" aria-label="Permalink to “IDENTIFIERS_AND_SCOPE.ID_DUP_IN_MODULE — Duplicate identifier in module”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Two declarations with same name (ports, wires, registers, consts, instances).</li><li>Fix: Rename one declaration; ensure uniqueness in module scope.</li></ul><h3 id="identifiers-and-scope-module-name-dup-in-project-—-module-name-not-unique-project-wide" tabindex="-1">IDENTIFIERS_AND_SCOPE.MODULE_NAME_DUP_IN_PROJECT — Module name not unique project-wide <a class="header-anchor" href="#identifiers-and-scope-module-name-dup-in-project-—-module-name-not-unique-project-wide" aria-label="Permalink to “IDENTIFIERS_AND_SCOPE.MODULE_NAME_DUP_IN_PROJECT — Module name not unique project-wide”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Rename module or resolve import duplication.</li></ul><h3 id="identifiers-and-scope-instance-name-dup-in-module-—-duplicate-instance-name" tabindex="-1">IDENTIFIERS_AND_SCOPE.INSTANCE_NAME_DUP_IN_MODULE — Duplicate instance name <a class="header-anchor" href="#identifiers-and-scope-instance-name-dup-in-module-—-duplicate-instance-name" aria-label="Permalink to “IDENTIFIERS_AND_SCOPE.INSTANCE_NAME_DUP_IN_MODULE — Duplicate instance name”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Use unique instance names.</li></ul><h3 id="identifiers-and-scope-instance-name-conflict-—-instance-name-conflicts-other-identifier" tabindex="-1">IDENTIFIERS_AND_SCOPE.INSTANCE_NAME_CONFLICT — Instance name conflicts other identifier <a class="header-anchor" href="#identifiers-and-scope-instance-name-conflict-—-instance-name-conflicts-other-identifier" aria-label="Permalink to “IDENTIFIERS_AND_SCOPE.INSTANCE_NAME_CONFLICT — Instance name conflicts other identifier”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Rename instance so it doesn&#39;t collide with port/wire/register/CONST.</li></ul><h3 id="identifiers-and-scope-undeclared-identifier-—-undeclared-name-used" tabindex="-1">IDENTIFIERS_AND_SCOPE.UNDECLARED_IDENTIFIER — Undeclared name used <a class="header-anchor" href="#identifiers-and-scope-undeclared-identifier-—-undeclared-name-used" aria-label="Permalink to “IDENTIFIERS_AND_SCOPE.UNDECLARED_IDENTIFIER — Undeclared name used”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Declare the identifier or correct the name.</li></ul><h3 id="identifiers-and-scope-ambiguous-reference-—-ambiguous-reference" tabindex="-1">IDENTIFIERS_AND_SCOPE.AMBIGUOUS_REFERENCE — Ambiguous reference <a class="header-anchor" href="#identifiers-and-scope-ambiguous-reference-—-ambiguous-reference" aria-label="Permalink to “IDENTIFIERS_AND_SCOPE.AMBIGUOUS_REFERENCE — Ambiguous reference”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Name could refer to multiple things without instance/qualification.</li><li>Fix: Qualify with <code>instance.port</code> or rename conflicting identifiers.</li></ul><hr><h2 id="const-config-global" tabindex="-1">CONST / CONFIG / GLOBAL <a class="header-anchor" href="#const-config-global" aria-label="Permalink to “CONST / CONFIG / GLOBAL”">​</a></h2><h3 id="const-rules-const-negative-or-nonint-—-const-invalid-value" tabindex="-1">CONST_RULES.CONST_NEGATIVE_OR_NONINT — CONST invalid value <a class="header-anchor" href="#const-rules-const-negative-or-nonint-—-const-invalid-value" aria-label="Permalink to “CONST_RULES.CONST_NEGATIVE_OR_NONINT — CONST invalid value”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Initialize CONST with nonnegative integer.</li></ul><h3 id="config-block-config-multiple-blocks-—-multiple-config-blocks" tabindex="-1">CONFIG_BLOCK.CONFIG_MULTIPLE_BLOCKS — Multiple CONFIG blocks <a class="header-anchor" href="#config-block-config-multiple-blocks-—-multiple-config-blocks" aria-label="Permalink to “CONFIG_BLOCK.CONFIG_MULTIPLE_BLOCKS — Multiple CONFIG blocks”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Merge into single CONFIG block.</li></ul><h3 id="config-block-config-forward-ref-—-config-forward-reference" tabindex="-1">CONFIG_BLOCK.CONFIG_FORWARD_REF — CONFIG forward reference <a class="header-anchor" href="#config-block-config-forward-ref-—-config-forward-reference" aria-label="Permalink to “CONFIG_BLOCK.CONFIG_FORWARD_REF — CONFIG forward reference”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: CONFIG entry references a later CONFIG entry.</li><li>Fix: Reorder entries or use computed constants appropriately.</li></ul><h3 id="config-block-config-used-where-forbidden-const-used-where-forbidden" tabindex="-1">CONFIG_BLOCK.CONFIG_USED_WHERE_FORBIDDEN / CONST_USED_WHERE_FORBIDDEN <a class="header-anchor" href="#config-block-config-used-where-forbidden-const-used-where-forbidden" aria-label="Permalink to “CONFIG_BLOCK.CONFIG_USED_WHERE_FORBIDDEN / CONST_USED_WHERE_FORBIDDEN”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: CONFIG/CONST used at runtime (in ASYNCHRONOUS/SYNCHRONOUS expressions).</li><li>Fix: Use @global sized literals for runtime values; CONFIG/CONST only for compile-time contexts.</li></ul><h3 id="config-block-const-string-in-numeric-context-—-string-const-config-in-numeric-context" tabindex="-1">CONFIG_BLOCK.CONST_STRING_IN_NUMERIC_CONTEXT — String CONST/CONFIG in numeric context <a class="header-anchor" href="#config-block-const-string-in-numeric-context-—-string-const-config-in-numeric-context" aria-label="Permalink to “CONFIG_BLOCK.CONST_STRING_IN_NUMERIC_CONTEXT — String CONST/CONFIG in numeric context”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: A string-valued CONST or CONFIG entry is used where a numeric expression is expected (e.g., in a width bracket <code>[STR_CONST]</code> or MEM depth).</li><li>Fix: Use a numeric CONST/CONFIG for integer contexts. String values are only valid in <code>@file()</code> path arguments.</li></ul><h3 id="config-block-const-numeric-in-string-context-—-numeric-const-config-in-string-context" tabindex="-1">CONFIG_BLOCK.CONST_NUMERIC_IN_STRING_CONTEXT — Numeric CONST/CONFIG in string context <a class="header-anchor" href="#config-block-const-numeric-in-string-context-—-numeric-const-config-in-string-context" aria-label="Permalink to “CONFIG_BLOCK.CONST_NUMERIC_IN_STRING_CONTEXT — Numeric CONST/CONFIG in string context”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: A numeric CONST or CONFIG entry is used where a string is expected (e.g., <code>@file(NUM_CONST)</code>).</li><li>Fix: Use a string CONST/CONFIG for <code>@file()</code> paths (e.g., <code>INIT_FILE = &quot;data.bin&quot;;</code>).</li></ul><h3 id="global-block-global-invalid-expr-type-—-global-constant-must-be-sized-literal" tabindex="-1">GLOBAL_BLOCK.GLOBAL_INVALID_EXPR_TYPE — Global constant must be sized literal <a class="header-anchor" href="#global-block-global-invalid-expr-type-—-global-constant-must-be-sized-literal" aria-label="Permalink to “GLOBAL_BLOCK.GLOBAL_INVALID_EXPR_TYPE — Global constant must be sized literal”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Define global constants as sized literals (e.g., <code>8&#39;hFF</code>).</li></ul><hr><h2 id="ports-wires-registers" tabindex="-1">Ports, Wires &amp; Registers <a class="header-anchor" href="#ports-wires-registers" aria-label="Permalink to “Ports, Wires &amp; Registers”">​</a></h2><h3 id="port-wire-register-decls-port-missing-width-—-port-declared-without-width" tabindex="-1">PORT_WIRE_REGISTER_DECLS.PORT_MISSING_WIDTH — Port declared without width <a class="header-anchor" href="#port-wire-register-decls-port-missing-width-—-port-declared-without-width" aria-label="Permalink to “PORT_WIRE_REGISTER_DECLS.PORT_MISSING_WIDTH — Port declared without width”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Add mandatory <code>[N]</code> width.</li></ul><h3 id="port-wire-register-decls-port-direction-mismatch-in-—-assigning-to-in-port" tabindex="-1">PORT_WIRE_REGISTER_DECLS.PORT_DIRECTION_MISMATCH_IN — Assigning to IN port <a class="header-anchor" href="#port-wire-register-decls-port-direction-mismatch-in-—-assigning-to-in-port" aria-label="Permalink to “PORT_WIRE_REGISTER_DECLS.PORT_DIRECTION_MISMATCH_IN — Assigning to IN port”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Writing to an <code>IN</code> port outside allowed INOUT tri‑state patterns.</li><li>Fix: Only read <code>IN</code> ports; if bidirectional behavior is needed use <code>INOUT</code> and tri‑state logic.</li></ul><h3 id="port-wire-register-decls-port-direction-mismatch-out-—-reading-from-out-port" tabindex="-1">PORT_WIRE_REGISTER_DECLS.PORT_DIRECTION_MISMATCH_OUT — Reading from OUT port <a class="header-anchor" href="#port-wire-register-decls-port-direction-mismatch-out-—-reading-from-out-port" aria-label="Permalink to “PORT_WIRE_REGISTER_DECLS.PORT_DIRECTION_MISMATCH_OUT — Reading from OUT port”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Reading an <code>OUT</code> port as if it were a driver.</li><li>Fix: Do not read module <code>OUT</code> ports inside the same module; use internal regs/wires for observation.</li></ul><h3 id="port-wire-register-decls-port-tristate-mismatch-—-z-assigned-to-non-inout" tabindex="-1">PORT_WIRE_REGISTER_DECLS.PORT_TRISTATE_MISMATCH — <code>z</code> assigned to non-INOUT <a class="header-anchor" href="#port-wire-register-decls-port-tristate-mismatch-—-z-assigned-to-non-inout" aria-label="Permalink to “PORT_WIRE_REGISTER_DECLS.PORT_TRISTATE_MISMATCH — z assigned to non-INOUT”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Only assign <code>z</code> to INOUT ports.</li></ul><h3 id="port-wire-register-decls-wire-multi-dimensional-reg-multi-dimensional-—-multi-dimensional-illegal" tabindex="-1">PORT_WIRE_REGISTER_DECLS.WIRE_MULTI_DIMENSIONAL / REG_MULTI_DIMENSIONAL — Multi-dimensional illegal <a class="header-anchor" href="#port-wire-register-decls-wire-multi-dimensional-reg-multi-dimensional-—-multi-dimensional-illegal" aria-label="Permalink to “PORT_WIRE_REGISTER_DECLS.WIRE_MULTI_DIMENSIONAL / REG_MULTI_DIMENSIONAL — Multi-dimensional illegal”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Use MEM for arrays; declare WIRE/REGISTER as single-dimensional scalars.</li></ul><h3 id="port-wire-register-decls-reg-missing-init-literal-—-register-missing-reset-literal" tabindex="-1">PORT_WIRE_REGISTER_DECLS.REG_MISSING_INIT_LITERAL — Register missing reset literal <a class="header-anchor" href="#port-wire-register-decls-reg-missing-init-literal-—-register-missing-reset-literal" aria-label="Permalink to “PORT_WIRE_REGISTER_DECLS.REG_MISSING_INIT_LITERAL — Register missing reset literal”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Provide a sized literal reset value (no <code>x</code> bits).</li></ul><h3 id="port-wire-register-decls-reg-init-contains-x-—-register-reset-contains-x" tabindex="-1">PORT_WIRE_REGISTER_DECLS.REG_INIT_CONTAINS_X — Register reset contains <code>x</code> <a class="header-anchor" href="#port-wire-register-decls-reg-init-contains-x-—-register-reset-contains-x" aria-label="Permalink to “PORT_WIRE_REGISTER_DECLS.REG_INIT_CONTAINS_X — Register reset contains x”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Use known 0/1 bits for reset; <code>x</code> not permitted.</li></ul><h3 id="port-wire-register-decls-reg-init-contains-z-—-register-reset-contains-z" tabindex="-1">PORT_WIRE_REGISTER_DECLS.REG_INIT_CONTAINS_Z — Register reset contains <code>z</code> <a class="header-anchor" href="#port-wire-register-decls-reg-init-contains-z-—-register-reset-contains-z" aria-label="Permalink to “PORT_WIRE_REGISTER_DECLS.REG_INIT_CONTAINS_Z — Register reset contains z”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Use known 0/1 bits for reset; <code>z</code> not permitted.</li></ul><h3 id="port-wire-register-decls-reg-init-width-mismatch-—-register-init-width-mismatch" tabindex="-1">PORT_WIRE_REGISTER_DECLS.REG_INIT_WIDTH_MISMATCH — Register init width mismatch <a class="header-anchor" href="#port-wire-register-decls-reg-init-width-mismatch-—-register-init-width-mismatch" aria-label="Permalink to “PORT_WIRE_REGISTER_DECLS.REG_INIT_WIDTH_MISMATCH — Register init width mismatch”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Init literal width must match declared register width.</li></ul><h3 id="port-wire-register-decls-write-wire-in-sync-—-writing-wire-in-synchronous" tabindex="-1">PORT_WIRE_REGISTER_DECLS.WRITE_WIRE_IN_SYNC — Writing wire in SYNCHRONOUS <a class="header-anchor" href="#port-wire-register-decls-write-wire-in-sync-—-writing-wire-in-synchronous" aria-label="Permalink to “PORT_WIRE_REGISTER_DECLS.WRITE_WIRE_IN_SYNC — Writing wire in SYNCHRONOUS”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Writes to wires must occur in ASYNCHRONOUS; registers are updated in SYNCHRONOUS blocks.</li></ul><h3 id="port-wire-register-decls-assign-to-non-register-in-sync-—-lhs-not-a-register-in-sync-assignment" tabindex="-1">PORT_WIRE_REGISTER_DECLS.ASSIGN_TO_NON_REGISTER_IN_SYNC — LHS not a register in sync assignment <a class="header-anchor" href="#port-wire-register-decls-assign-to-non-register-in-sync-—-lhs-not-a-register-in-sync-assignment" aria-label="Permalink to “PORT_WIRE_REGISTER_DECLS.ASSIGN_TO_NON_REGISTER_IN_SYNC — LHS not a register in sync assignment”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Use a REGISTER on LHS for synchronous assignments.</li></ul><h3 id="port-wire-register-decls-module-missing-port-module-port-in-only" tabindex="-1">PORT_WIRE_REGISTER_DECLS.MODULE_MISSING_PORT / MODULE_PORT_IN_ONLY <a class="header-anchor" href="#port-wire-register-decls-module-missing-port-module-port-in-only" aria-label="Permalink to “PORT_WIRE_REGISTER_DECLS.MODULE_MISSING_PORT / MODULE_PORT_IN_ONLY”">​</a></h3><ul><li>Severity: ERROR / WARN</li><li>Fix: Ensure module declares PORT block and includes outputs if expected; a module with only IN ports may be dead code.</li></ul><hr><h2 id="modules-instantiation" tabindex="-1">Modules &amp; Instantiation <a class="header-anchor" href="#modules-instantiation" aria-label="Permalink to “Modules &amp; Instantiation”">​</a></h2><h3 id="module-and-instantiation-instance-missing-port-—-not-all-child-ports-listed-in-new" tabindex="-1">MODULE_AND_INSTANTIATION.INSTANCE_MISSING_PORT — Not all child ports listed in @new <a class="header-anchor" href="#module-and-instantiation-instance-missing-port-—-not-all-child-ports-listed-in-new" aria-label="Permalink to “MODULE_AND_INSTANTIATION.INSTANCE_MISSING_PORT — Not all child ports listed in @new”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Include all child ports in the <code>@new</code> instantiation block.</li></ul><h3 id="module-and-instantiation-instance-port-width-mismatch-—-port-width-mismatch" tabindex="-1">MODULE_AND_INSTANTIATION.INSTANCE_PORT_WIDTH_MISMATCH — Port width mismatch <a class="header-anchor" href="#module-and-instantiation-instance-port-width-mismatch-—-port-width-mismatch" aria-label="Permalink to “MODULE_AND_INSTANTIATION.INSTANCE_PORT_WIDTH_MISMATCH — Port width mismatch”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Ensure evaluated widths (after OVERRIDE) match between parent binding and child port.</li></ul><h3 id="module-and-instantiation-instance-port-direction-mismatch-—-direction-mismatch" tabindex="-1">MODULE_AND_INSTANTIATION.INSTANCE_PORT_DIRECTION_MISMATCH — Direction mismatch <a class="header-anchor" href="#module-and-instantiation-instance-port-direction-mismatch-—-direction-mismatch" aria-label="Permalink to “MODULE_AND_INSTANTIATION.INSTANCE_PORT_DIRECTION_MISMATCH — Direction mismatch”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Connect IN ports to drivers, OUT ports to sinks or parent signals with correct roles; respect pin category.</li></ul><h3 id="module-and-instantiation-instance-override-const-undefined-—-override-targets-unknown" tabindex="-1">MODULE_AND_INSTANTIATION.INSTANCE_OVERRIDE_CONST_UNDEFINED — Override targets unknown <a class="header-anchor" href="#module-and-instantiation-instance-override-const-undefined-—-override-targets-unknown" aria-label="Permalink to “MODULE_AND_INSTANTIATION.INSTANCE_OVERRIDE_CONST_UNDEFINED — Override targets unknown”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Only override CONST names that exist in the child module.</li></ul><h3 id="module-and-instantiation-instance-parent-signal-width-mismatch-—-parent-signal-width-wrong" tabindex="-1">MODULE_AND_INSTANTIATION.INSTANCE_PARENT_SIGNAL_WIDTH_MISMATCH — Parent signal width wrong <a class="header-anchor" href="#module-and-instantiation-instance-parent-signal-width-mismatch-—-parent-signal-width-wrong" aria-label="Permalink to “MODULE_AND_INSTANTIATION.INSTANCE_PARENT_SIGNAL_WIDTH_MISMATCH — Parent signal width wrong”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Ensure parent signal has the width declared in instantiation clause (check parent&#39;s CONST resolution).</li></ul><hr><h2 id="mux-rules" tabindex="-1">MUX Rules <a class="header-anchor" href="#mux-rules" aria-label="Permalink to “MUX Rules”">​</a></h2><h3 id="mux-rules-mux-assign-lhs-—-assigning-to-mux-is-forbidden" tabindex="-1">MUX_RULES.MUX_ASSIGN_LHS — Assigning to MUX is forbidden <a class="header-anchor" href="#mux-rules-mux-assign-lhs-—-assigning-to-mux-is-forbidden" aria-label="Permalink to “MUX_RULES.MUX_ASSIGN_LHS — Assigning to MUX is forbidden”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Treat MUX only as read-only source; create a wire/register to hold selected data if you must drive it.</li></ul><h3 id="mux-rules-mux-agg-source-width-mismatch-—-aggregation-widths-differ" tabindex="-1">MUX_RULES.MUX_AGG_SOURCE_WIDTH_MISMATCH — Aggregation widths differ <a class="header-anchor" href="#mux-rules-mux-agg-source-width-mismatch-—-aggregation-widths-differ" aria-label="Permalink to “MUX_RULES.MUX_AGG_SOURCE_WIDTH_MISMATCH — Aggregation widths differ”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Make all aggregated sources identical width before declaring the MUX.</li></ul><h3 id="mux-rules-mux-slice-width-not-divisor-—-auto-slicing-invalid-partition" tabindex="-1">MUX_RULES.MUX_SLICE_WIDTH_NOT_DIVISOR — Auto-slicing invalid partition <a class="header-anchor" href="#mux-rules-mux-slice-width-not-divisor-—-auto-slicing-invalid-partition" aria-label="Permalink to “MUX_RULES.MUX_SLICE_WIDTH_NOT_DIVISOR — Auto-slicing invalid partition”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Choose element_width that exactly divides wide_source width.</li></ul><h3 id="mux-rules-mux-selector-out-of-range-const-—-selector-statically-out-of-range" tabindex="-1">MUX_RULES.MUX_SELECTOR_OUT_OF_RANGE_CONST — Selector statically out of range <a class="header-anchor" href="#mux-rules-mux-selector-out-of-range-const-—-selector-statically-out-of-range" aria-label="Permalink to “MUX_RULES.MUX_SELECTOR_OUT_OF_RANGE_CONST — Selector statically out of range”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Correct selector width or bounds; ensure compile-time indices fall within valid range.</li></ul><hr><h2 id="assignments-exclusive-assignment-rule" tabindex="-1">Assignments &amp; Exclusive Assignment Rule <a class="header-anchor" href="#assignments-exclusive-assignment-rule" aria-label="Permalink to “Assignments &amp; Exclusive Assignment Rule”">​</a></h2><h3 id="assignments-and-exclusive-assign-width-no-modifier-—-width-mismatch-without-z-s" tabindex="-1">ASSIGNMENTS_AND_EXCLUSIVE.ASSIGN_WIDTH_NO_MODIFIER — Width mismatch without z/s <a class="header-anchor" href="#assignments-and-exclusive-assign-width-no-modifier-—-width-mismatch-without-z-s" aria-label="Permalink to “ASSIGNMENTS_AND_EXCLUSIVE.ASSIGN_WIDTH_NO_MODIFIER — Width mismatch without z/s”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: <code>=</code>, <code>=&gt;</code>, <code>&lt;=</code> used when widths differ (modifier required).</li><li>Fix: Use <code>=z</code>/<code>=s</code>, <code>=&gt;z</code>/<code>=&gt;s</code>, or resize operands so widths match.</li></ul><h3 id="assignments-and-exclusive-assign-truncates-—-assignment-would-truncate-rhs" tabindex="-1">ASSIGNMENTS_AND_EXCLUSIVE.ASSIGN_TRUNCATES — Assignment would truncate RHS <a class="header-anchor" href="#assignments-and-exclusive-assign-truncates-—-assignment-would-truncate-rhs" aria-label="Permalink to “ASSIGNMENTS_AND_EXCLUSIVE.ASSIGN_TRUNCATES — Assignment would truncate RHS”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Prevent truncation by slicing explicitly or making LHS wide enough; avoid implicit truncation.</li></ul><h3 id="assignments-and-exclusive-assign-slice-width-mismatch-—-slice-width-mismatch" tabindex="-1">ASSIGNMENTS_AND_EXCLUSIVE.ASSIGN_SLICE_WIDTH_MISMATCH — Slice width mismatch <a class="header-anchor" href="#assignments-and-exclusive-assign-slice-width-mismatch-—-slice-width-mismatch" aria-label="Permalink to “ASSIGNMENTS_AND_EXCLUSIVE.ASSIGN_SLICE_WIDTH_MISMATCH — Slice width mismatch”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Ensure source expression width equals the slice width.</li></ul><h3 id="assignments-and-exclusive-assign-concat-width-mismatch-—-concatenation-width-mismatch" tabindex="-1">ASSIGNMENTS_AND_EXCLUSIVE.ASSIGN_CONCAT_WIDTH_MISMATCH — Concatenation width mismatch <a class="header-anchor" href="#assignments-and-exclusive-assign-concat-width-mismatch-—-concatenation-width-mismatch" aria-label="Permalink to “ASSIGNMENTS_AND_EXCLUSIVE.ASSIGN_CONCAT_WIDTH_MISMATCH — Concatenation width mismatch”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Make expression width equal sum of LHS part widths (or use extension modifiers if allowed).</li></ul><h3 id="assignments-and-exclusive-assign-multiple-same-bits-—-exclusive-assignment-violation" tabindex="-1">ASSIGNMENTS_AND_EXCLUSIVE.ASSIGN_MULTIPLE_SAME_BITS — Exclusive assignment violation <a class="header-anchor" href="#assignments-and-exclusive-assign-multiple-same-bits-—-exclusive-assignment-violation" aria-label="Permalink to “ASSIGNMENTS_AND_EXCLUSIVE.ASSIGN_MULTIPLE_SAME_BITS — Exclusive assignment violation”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: More than one assignment to same bits along some execution path.</li><li>Fix: Rework control flow so assignments are in mutually exclusive branches or merge into a single assignment using ternary/select.</li></ul><h3 id="assignments-and-exclusive-assign-independent-if-select-—-independent-chains-conflict" tabindex="-1">ASSIGNMENTS_AND_EXCLUSIVE.ASSIGN_INDEPENDENT_IF_SELECT — Independent chains conflict <a class="header-anchor" href="#assignments-and-exclusive-assign-independent-if-select-—-independent-chains-conflict" aria-label="Permalink to “ASSIGNMENTS_AND_EXCLUSIVE.ASSIGN_INDEPENDENT_IF_SELECT — Independent chains conflict”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Separate IF chains at same nesting level each assign same identifier (compiler treats as concurrent).</li><li>Fix: Combine into single SELECT/IF/ELIF chain or restructure to make assignments exclusive.</li></ul><h3 id="assignments-and-exclusive-assign-shadowing-—-shadowing-assignment-root-nested" tabindex="-1">ASSIGNMENTS_AND_EXCLUSIVE.ASSIGN_SHADOWING — Shadowing assignment (root + nested) <a class="header-anchor" href="#assignments-and-exclusive-assign-shadowing-—-shadowing-assignment-root-nested" aria-label="Permalink to “ASSIGNMENTS_AND_EXCLUSIVE.ASSIGN_SHADOWING — Shadowing assignment (root + nested)”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Avoid assigning at root and again in nested blocks to same bits; use conditional assignments consistently.</li></ul><h3 id="assignments-and-exclusive-assign-slice-overlap-—-overlapping-part-selects-assigned-in-same-path" tabindex="-1">ASSIGNMENTS_AND_EXCLUSIVE.ASSIGN_SLICE_OVERLAP — Overlapping part-selects assigned in same path <a class="header-anchor" href="#assignments-and-exclusive-assign-slice-overlap-—-overlapping-part-selects-assigned-in-same-path" aria-label="Permalink to “ASSIGNMENTS_AND_EXCLUSIVE.ASSIGN_SLICE_OVERLAP — Overlapping part-selects assigned in same path”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Ensure part-selects are non-overlapping on any execution path or combine into single concatenation assignment.</li></ul><h3 id="assignments-and-exclusive-async-undefined-path-no-driver-—-async-leaves-net-without-driver" tabindex="-1">ASSIGNMENTS_AND_EXCLUSIVE.ASYNC_UNDEFINED_PATH_NO_DRIVER — ASYNC leaves net without driver <a class="header-anchor" href="#assignments-and-exclusive-async-undefined-path-no-driver-—-async-leaves-net-without-driver" aria-label="Permalink to “ASSIGNMENTS_AND_EXCLUSIVE.ASYNC_UNDEFINED_PATH_NO_DRIVER — ASYNC leaves net without driver”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Conditional ASYNCHRONOUS assignment path leaves a wire/port undriven (no ELSE) and no other driver exists.</li><li>Fix: Provide DEFAULT branch or alternate driver; ensure every execution path that reads the net has a driver.</li></ul><hr><h2 id="asynchronous-block-rules" tabindex="-1">ASYNCHRONOUS Block Rules <a class="header-anchor" href="#asynchronous-block-rules" aria-label="Permalink to “ASYNCHRONOUS Block Rules”">​</a></h2><h3 id="async-block-rules-async-invalid-statement-target-—-lhs-not-assignable" tabindex="-1">ASYNC_BLOCK_RULES.ASYNC_INVALID_STATEMENT_TARGET — LHS not assignable <a class="header-anchor" href="#async-block-rules-async-invalid-statement-target-—-lhs-not-assignable" aria-label="Permalink to “ASYNC_BLOCK_RULES.ASYNC_INVALID_STATEMENT_TARGET — LHS not assignable”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: LHS must be assignable (wire, port, register current-value read in ASYNC can&#39;t be written there).</li></ul><h3 id="async-block-rules-async-assign-register-—-register-written-in-asynchronous" tabindex="-1">ASYNC_BLOCK_RULES.ASYNC_ASSIGN_REGISTER — Register written in ASYNCHRONOUS <a class="header-anchor" href="#async-block-rules-async-assign-register-—-register-written-in-asynchronous" aria-label="Permalink to “ASYNC_BLOCK_RULES.ASYNC_ASSIGN_REGISTER — Register written in ASYNCHRONOUS”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Move register writes into SYNCHRONOUS blocks.</li></ul><h3 id="async-block-rules-async-alias-literal-rhs-—-alias-with-literal-rhs-in-async" tabindex="-1">ASYNC_BLOCK_RULES.ASYNC_ALIAS_LITERAL_RHS — Alias with literal RHS in ASYNC <a class="header-anchor" href="#async-block-rules-async-alias-literal-rhs-—-alias-with-literal-rhs-in-async" aria-label="Permalink to “ASYNC_BLOCK_RULES.ASYNC_ALIAS_LITERAL_RHS — Alias with literal RHS in ASYNC”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Using <code>a = 1&#39;b1;</code> in ASYNCHRONOUS is forbidden (alias RHS must not be bare literal).</li><li>Fix: Use directional drive <code>a &lt;= 1&#39;b1;</code> or <code>a =&gt; 1&#39;b1;</code> instead.</li></ul><h3 id="async-block-rules-async-floating-z-read-—-all-drivers-z-on-read" tabindex="-1">ASYNC_BLOCK_RULES.ASYNC_FLOATING_Z_READ — All drivers <code>z</code> on read <a class="header-anchor" href="#async-block-rules-async-floating-z-read-—-all-drivers-z-on-read" aria-label="Permalink to “ASYNC_BLOCK_RULES.ASYNC_FLOATING_Z_READ — All drivers z on read”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Ensure at least one driver supplies 0/1 for read conditions or avoid reading when bus released.</li></ul><hr><h2 id="synchronous-block-rules" tabindex="-1">SYNCHRONOUS Block Rules <a class="header-anchor" href="#synchronous-block-rules" aria-label="Permalink to “SYNCHRONOUS Block Rules”">​</a></h2><h3 id="sync-block-rules-sync-multi-assign-same-reg-bits-—-multiple-reg-assignments-in-path" tabindex="-1">SYNC_BLOCK_RULES.SYNC_MULTI_ASSIGN_SAME_REG_BITS — Multiple reg assignments in path <a class="header-anchor" href="#sync-block-rules-sync-multi-assign-same-reg-bits-—-multiple-reg-assignments-in-path" aria-label="Permalink to “SYNC_BLOCK_RULES.SYNC_MULTI_ASSIGN_SAME_REG_BITS — Multiple reg assignments in path”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Ensure each register bit assigned at most once per path; move assignments into mutually exclusive branches or combine.</li></ul><h3 id="sync-block-rules-sync-root-and-conditional-assign-—-root-conditional-conflict" tabindex="-1">SYNC_BLOCK_RULES.SYNC_ROOT_AND_CONDITIONAL_ASSIGN — Root + conditional conflict <a class="header-anchor" href="#sync-block-rules-sync-root-and-conditional-assign-—-root-conditional-conflict" aria-label="Permalink to “SYNC_BLOCK_RULES.SYNC_ROOT_AND_CONDITIONAL_ASSIGN — Root + conditional conflict”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Do not assign same register at root and inside nested condition; place all domain assignments within consistent conditional structure.</li></ul><h3 id="sync-block-rules-sync-slice-width-mismatch-—-register-slice-width-mismatch" tabindex="-1">SYNC_BLOCK_RULES.SYNC_SLICE_WIDTH_MISMATCH — Register slice width mismatch <a class="header-anchor" href="#sync-block-rules-sync-slice-width-mismatch-—-register-slice-width-mismatch" aria-label="Permalink to “SYNC_BLOCK_RULES.SYNC_SLICE_WIDTH_MISMATCH — Register slice width mismatch”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Ensure RHS width equals slice width.</li></ul><h3 id="sync-block-rules-sync-concat-dup-reg-—-concatenation-contains-same-register-multiple-times" tabindex="-1">SYNC_BLOCK_RULES.SYNC_CONCAT_DUP_REG — Concatenation contains same register multiple times <a class="header-anchor" href="#sync-block-rules-sync-concat-dup-reg-—-concatenation-contains-same-register-multiple-times" aria-label="Permalink to “SYNC_BLOCK_RULES.SYNC_CONCAT_DUP_REG — Concatenation contains same register multiple times”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Use unique registers in concatenation LHS.</li></ul><h3 id="sync-block-rules-sync-no-alias-—-aliasing-not-allowed-in-synchronous-blocks" tabindex="-1">SYNC_BLOCK_RULES.SYNC_NO_ALIAS — Aliasing not allowed in synchronous blocks <a class="header-anchor" href="#sync-block-rules-sync-no-alias-—-aliasing-not-allowed-in-synchronous-blocks" aria-label="Permalink to “SYNC_BLOCK_RULES.SYNC_NO_ALIAS — Aliasing not allowed in synchronous blocks”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Use directional operators (<code>&lt;=</code>, <code>=&gt;</code>) only; alias operators are forbidden in SYNCHRONOUS.</li></ul><h3 id="sync-block-rules-domain-conflict-multi-clk-assign-duplicate-block-—-clock-cdc-domain-errors" tabindex="-1">SYNC_BLOCK_RULES.DOMAIN_CONFLICT / MULTI_CLK_ASSIGN / DUPLICATE_BLOCK — Clock/CDC domain errors <a class="header-anchor" href="#sync-block-rules-domain-conflict-multi-clk-assign-duplicate-block-—-clock-cdc-domain-errors" aria-label="Permalink to “SYNC_BLOCK_RULES.DOMAIN_CONFLICT / MULTI_CLK_ASSIGN / DUPLICATE_BLOCK — Clock/CDC domain errors”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Register read/write used in block whose <code>CLK</code> doesn&#39;t match home domain; same register assigned in different clock blocks; duplicate synchronous block for a clock.</li><li>Fix: Respect Register locality/home-domain rules; use CDC entries to cross domains; consolidate per-clock logic into single SYNCHRONOUS block.</li></ul><h3 id="sync-block-rules-cdc-source-not-register-cdc-bit-width-not-1" tabindex="-1">SYNC_BLOCK_RULES.CDC_SOURCE_NOT_REGISTER / CDC_BIT_WIDTH_NOT_1 <a class="header-anchor" href="#sync-block-rules-cdc-source-not-register-cdc-bit-width-not-1" aria-label="Permalink to “SYNC_BLOCK_RULES.CDC_SOURCE_NOT_REGISTER / CDC_BIT_WIDTH_NOT_1”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: CDC sources must be <code>REGISTER</code>; BIT type registers must have width 1.</li></ul><h3 id="sync-block-rules-sync-clk-width-not-1-—-clock-signal-not-width-1" tabindex="-1">SYNC_BLOCK_RULES.SYNC_CLK_WIDTH_NOT_1 — Clock signal not width-1 <a class="header-anchor" href="#sync-block-rules-sync-clk-width-not-1-—-clock-signal-not-width-1" aria-label="Permalink to “SYNC_BLOCK_RULES.SYNC_CLK_WIDTH_NOT_1 — Clock signal not width-1”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: SYNCHRONOUS CLK signal must have width [1].</li></ul><h3 id="sync-block-rules-sync-missing-clk-—-missing-clk-parameter" tabindex="-1">SYNC_BLOCK_RULES.SYNC_MISSING_CLK — Missing CLK parameter <a class="header-anchor" href="#sync-block-rules-sync-missing-clk-—-missing-clk-parameter" aria-label="Permalink to “SYNC_BLOCK_RULES.SYNC_MISSING_CLK — Missing CLK parameter”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: SYNCHRONOUS block must declare a CLK parameter.</li></ul><h3 id="sync-block-rules-sync-edge-invalid-—-invalid-edge-value" tabindex="-1">SYNC_BLOCK_RULES.SYNC_EDGE_INVALID — Invalid edge value <a class="header-anchor" href="#sync-block-rules-sync-edge-invalid-—-invalid-edge-value" aria-label="Permalink to “SYNC_BLOCK_RULES.SYNC_EDGE_INVALID — Invalid edge value”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: EDGE must be Rising, Falling, or Both.</li></ul><h3 id="sync-block-rules-sync-reset-active-invalid-—-invalid-reset-active" tabindex="-1">SYNC_BLOCK_RULES.SYNC_RESET_ACTIVE_INVALID — Invalid RESET_ACTIVE <a class="header-anchor" href="#sync-block-rules-sync-reset-active-invalid-—-invalid-reset-active" aria-label="Permalink to “SYNC_BLOCK_RULES.SYNC_RESET_ACTIVE_INVALID — Invalid RESET_ACTIVE”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: RESET_ACTIVE must be High or Low.</li></ul><h3 id="sync-block-rules-sync-reset-type-invalid-—-invalid-reset-type" tabindex="-1">SYNC_BLOCK_RULES.SYNC_RESET_TYPE_INVALID — Invalid RESET_TYPE <a class="header-anchor" href="#sync-block-rules-sync-reset-type-invalid-—-invalid-reset-type" aria-label="Permalink to “SYNC_BLOCK_RULES.SYNC_RESET_TYPE_INVALID — Invalid RESET_TYPE”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: RESET_TYPE must be Clocked or Immediate.</li></ul><h3 id="sync-block-rules-sync-reset-width-not-1-—-reset-signal-not-width-1" tabindex="-1">SYNC_BLOCK_RULES.SYNC_RESET_WIDTH_NOT_1 — Reset signal not width-1 <a class="header-anchor" href="#sync-block-rules-sync-reset-width-not-1-—-reset-signal-not-width-1" aria-label="Permalink to “SYNC_BLOCK_RULES.SYNC_RESET_WIDTH_NOT_1 — Reset signal not width-1”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: RESET signal must have width [1].</li></ul><h3 id="sync-block-rules-sync-unknown-param-—-unknown-synchronous-parameter" tabindex="-1">SYNC_BLOCK_RULES.SYNC_UNKNOWN_PARAM — Unknown SYNCHRONOUS parameter <a class="header-anchor" href="#sync-block-rules-sync-unknown-param-—-unknown-synchronous-parameter" aria-label="Permalink to “SYNC_BLOCK_RULES.SYNC_UNKNOWN_PARAM — Unknown SYNCHRONOUS parameter”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Valid parameters are CLK, RESET, EDGE, RESET_ACTIVE, RESET_TYPE.</li></ul><h3 id="sync-block-rules-sync-edge-both-warning-—-dual-edge-clocking-warning" tabindex="-1">SYNC_BLOCK_RULES.SYNC_EDGE_BOTH_WARNING — Dual-edge clocking warning <a class="header-anchor" href="#sync-block-rules-sync-edge-both-warning-—-dual-edge-clocking-warning" aria-label="Permalink to “SYNC_BLOCK_RULES.SYNC_EDGE_BOTH_WARNING — Dual-edge clocking warning”">​</a></h3><ul><li>Severity: WARN</li><li>Cause: EDGE=Both may not be supported by all FPGA architectures.</li><li>Fix: Use Rising or Falling unless dual-edge is intentional.</li></ul><h3 id="sync-block-rules-cdc-source-not-plain-reg-cdc-dest-alias-assigned-cdc-stages-invalid-cdc-type-invalid-cdc-raw-stages-forbidden-cdc-pulse-width-not-1-cdc-dest-alias-dup" tabindex="-1">SYNC_BLOCK_RULES.CDC_SOURCE_NOT_PLAIN_REG / CDC_DEST_ALIAS_ASSIGNED / CDC_STAGES_INVALID / CDC_TYPE_INVALID / CDC_RAW_STAGES_FORBIDDEN / CDC_PULSE_WIDTH_NOT_1 / CDC_DEST_ALIAS_DUP <a class="header-anchor" href="#sync-block-rules-cdc-source-not-plain-reg-cdc-dest-alias-assigned-cdc-stages-invalid-cdc-type-invalid-cdc-raw-stages-forbidden-cdc-pulse-width-not-1-cdc-dest-alias-dup" aria-label="Permalink to “SYNC_BLOCK_RULES.CDC_SOURCE_NOT_PLAIN_REG / CDC_DEST_ALIAS_ASSIGNED / CDC_STAGES_INVALID / CDC_TYPE_INVALID / CDC_RAW_STAGES_FORBIDDEN / CDC_PULSE_WIDTH_NOT_1 / CDC_DEST_ALIAS_DUP”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: CDC source must be a plain register identifier (not slice/expression). Destination alias is read-only. Stages must be positive. Type must be BIT/BUS/FIFO/HANDSHAKE/PULSE/MCP/RAW. RAW has no stages parameter. PULSE source must be width 1. Dest alias name must be unique.</li></ul><hr><h2 id="control-flow-if-select" tabindex="-1">Control Flow (IF / SELECT) <a class="header-anchor" href="#control-flow-if-select" aria-label="Permalink to “Control Flow (IF / SELECT)”">​</a></h2><h3 id="control-flow-if-select-if-cond-width-not-1-—-if-elif-condition-width-1" tabindex="-1">CONTROL_FLOW_IF_SELECT.IF_COND_WIDTH_NOT_1 — IF/ELIF condition width ≠ 1 <a class="header-anchor" href="#control-flow-if-select-if-cond-width-not-1-—-if-elif-condition-width-1" aria-label="Permalink to “CONTROL_FLOW_IF_SELECT.IF_COND_WIDTH_NOT_1 — IF/ELIF condition width ≠ 1”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Ensure condition expression reduces to 1 bit (e.g., compare equality).</li></ul><h3 id="control-flow-if-select-control-flow-outside-block-—-if-select-used-outside-block" tabindex="-1">CONTROL_FLOW_IF_SELECT.CONTROL_FLOW_OUTSIDE_BLOCK — IF/SELECT used outside block <a class="header-anchor" href="#control-flow-if-select-control-flow-outside-block-—-if-select-used-outside-block" aria-label="Permalink to “CONTROL_FLOW_IF_SELECT.CONTROL_FLOW_OUTSIDE_BLOCK — IF/SELECT used outside block”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Place control flow inside ASYNCHRONOUS or SYNCHRONOUS blocks.</li></ul><h3 id="control-flow-if-select-select-dup-case-value-—-duplicate-case-label" tabindex="-1">CONTROL_FLOW_IF_SELECT.SELECT_DUP_CASE_VALUE — Duplicate CASE label <a class="header-anchor" href="#control-flow-if-select-select-dup-case-value-—-duplicate-case-label" aria-label="Permalink to “CONTROL_FLOW_IF_SELECT.SELECT_DUP_CASE_VALUE — Duplicate CASE label”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Remove or collapse duplicate CASE labels.</li></ul><h3 id="control-flow-if-select-async-alias-in-conditional-—-alias-operator-inside-conditional" tabindex="-1">CONTROL_FLOW_IF_SELECT.ASYNC_ALIAS_IN_CONDITIONAL — Alias operator inside conditional <a class="header-anchor" href="#control-flow-if-select-async-alias-in-conditional-—-alias-operator-inside-conditional" aria-label="Permalink to “CONTROL_FLOW_IF_SELECT.ASYNC_ALIAS_IN_CONDITIONAL — Alias operator inside conditional”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Use conditional expressions or directional assignments; aliasing is for unconditional net merges only.</li></ul><h3 id="control-flow-if-select-select-default-recommended-async-—-missing-default-in-asynchronous-select" tabindex="-1">CONTROL_FLOW_IF_SELECT.SELECT_DEFAULT_RECOMMENDED_ASYNC — Missing DEFAULT in ASYNCHRONOUS SELECT <a class="header-anchor" href="#control-flow-if-select-select-default-recommended-async-—-missing-default-in-asynchronous-select" aria-label="Permalink to “CONTROL_FLOW_IF_SELECT.SELECT_DEFAULT_RECOMMENDED_ASYNC — Missing DEFAULT in ASYNCHRONOUS SELECT”">​</a></h3><ul><li>Severity: WARN</li><li>Cause: May leave nets floating for some selector values.</li><li>Fix: Add DEFAULT clause and specify safe values.</li></ul><hr><h2 id="functions-compile-time-utilities" tabindex="-1">Functions &amp; Compile-time Utilities <a class="header-anchor" href="#functions-compile-time-utilities" aria-label="Permalink to “Functions &amp; Compile-time Utilities”">​</a></h2><h3 id="functions-and-clog2-clog2-nonpositive-arg-—-clog2-arg-≤-0" tabindex="-1">FUNCTIONS_AND_CLOG2.CLOG2_NONPOSITIVE_ARG — clog2 arg ≤ 0 <a class="header-anchor" href="#functions-and-clog2-clog2-nonpositive-arg-—-clog2-arg-≤-0" aria-label="Permalink to “FUNCTIONS_AND_CLOG2.CLOG2_NONPOSITIVE_ARG — clog2 arg ≤ 0”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Provide positive integer argument.</li></ul><h3 id="functions-and-clog2-clog2-invalid-context-—-clog2-used-at-runtime" tabindex="-1">FUNCTIONS_AND_CLOG2.CLOG2_INVALID_CONTEXT — clog2 used at runtime <a class="header-anchor" href="#functions-and-clog2-clog2-invalid-context-—-clog2-used-at-runtime" aria-label="Permalink to “FUNCTIONS_AND_CLOG2.CLOG2_INVALID_CONTEXT — clog2 used at runtime”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Use clog2 only in compile-time contexts (widths, CONST initializers, OVERRIDE). For runtime indexing use other constructs.</li></ul><h3 id="functions-and-clog2-widthof-invalid-context-—-widthof-used-at-runtime" tabindex="-1">FUNCTIONS_AND_CLOG2.WIDTHOF_INVALID_CONTEXT — widthof used at runtime <a class="header-anchor" href="#functions-and-clog2-widthof-invalid-context-—-widthof-used-at-runtime" aria-label="Permalink to “FUNCTIONS_AND_CLOG2.WIDTHOF_INVALID_CONTEXT — widthof used at runtime”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Use widthof only in compile-time contexts.</li></ul><h3 id="functions-and-clog2-func-result-truncated-silently-—-function-result-truncated-by-assignment" tabindex="-1">FUNCTIONS_AND_CLOG2.FUNC_RESULT_TRUNCATED_SILENTLY — Function result truncated by assignment <a class="header-anchor" href="#functions-and-clog2-func-result-truncated-silently-—-function-result-truncated-by-assignment" aria-label="Permalink to “FUNCTIONS_AND_CLOG2.FUNC_RESULT_TRUNCATED_SILENTLY — Function result truncated by assignment”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Check sizes of intrinsic operator results and assign to matching width or slice explicitly.</li></ul><hr><h2 id="net-drivers-tri‐state-observability" tabindex="-1">Net Drivers, Tri‑State &amp; Observability <a class="header-anchor" href="#net-drivers-tri‐state-observability" aria-label="Permalink to “Net Drivers, Tri‑State &amp; Observability”">​</a></h2><h3 id="net-drivers-and-tri-state-net-floating-with-sink-—-net-has-sinks-but-zero-active-drivers" tabindex="-1">NET_DRIVERS_AND_TRI_STATE.NET_FLOATING_WITH_SINK — Net has sinks but zero active drivers <a class="header-anchor" href="#net-drivers-and-tri-state-net-floating-with-sink-—-net-has-sinks-but-zero-active-drivers" aria-label="Permalink to “NET_DRIVERS_AND_TRI_STATE.NET_FLOATING_WITH_SINK — Net has sinks but zero active drivers”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Provide a driver on all execution paths that read the net (or avoid reading when released).</li></ul><h3 id="net-drivers-and-tri-state-net-tri-state-all-z-read-—-all-drivers-z-while-read" tabindex="-1">NET_DRIVERS_AND_TRI_STATE.NET_TRI_STATE_ALL_Z_READ — All drivers <code>z</code> while read <a class="header-anchor" href="#net-drivers-and-tri-state-net-tri-state-all-z-read-—-all-drivers-z-while-read" aria-label="Permalink to “NET_DRIVERS_AND_TRI_STATE.NET_TRI_STATE_ALL_Z_READ — All drivers z while read”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Ensure at least one driver provides known 0/1 at the moment of any read.</li></ul><h3 id="net-drivers-and-tri-state-net-dangling-unused-—-net-declared-with-no-drivers-and-no-sinks" tabindex="-1">NET_DRIVERS_AND_TRI_STATE.NET_DANGLING_UNUSED — Net declared with no drivers and no sinks <a class="header-anchor" href="#net-drivers-and-tri-state-net-dangling-unused-—-net-declared-with-no-drivers-and-no-sinks" aria-label="Permalink to “NET_DRIVERS_AND_TRI_STATE.NET_DANGLING_UNUSED — Net declared with no drivers and no sinks”">​</a></h3><ul><li>Severity: WARN</li><li>Fix: Remove unused declaration or add intended drivers/sinks.</li></ul><h3 id="observability-x-obs-x-to-observable-sink-—-x-bits-reach-observable-sink" tabindex="-1">OBSERVABILITY_X.OBS_X_TO_OBSERVABLE_SINK — x bits reach observable sink <a class="header-anchor" href="#observability-x-obs-x-to-observable-sink-—-x-bits-reach-observable-sink" aria-label="Permalink to “OBSERVABILITY_X.OBS_X_TO_OBSERVABLE_SINK — x bits reach observable sink”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Expression containing <code>x</code> used where its <code>x</code> bits could reach REGISTER init, MEM init, OUT/INOUT port, or top-level pin.</li><li>Fix: Mask structurally (not algebraically) before observable sinks (e.g., use conditional logic to drive defined values), or avoid <code>x</code> in those values.</li></ul><hr><h2 id="combinational-loops" tabindex="-1">Combinational Loops <a class="header-anchor" href="#combinational-loops" aria-label="Permalink to “Combinational Loops”">​</a></h2><h3 id="combinational-loops-comb-loop-unconditional-—-flow-sensitive-comb-loop-error" tabindex="-1">COMBINATIONAL_LOOPS.COMB_LOOP_UNCONDITIONAL — Flow-sensitive comb loop (error) <a class="header-anchor" href="#combinational-loops-comb-loop-unconditional-—-flow-sensitive-comb-loop-error" aria-label="Permalink to “COMBINATIONAL_LOOPS.COMB_LOOP_UNCONDITIONAL — Flow-sensitive comb loop (error)”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Unconditional cycle in ASYNCHRONOUS assignments (e.g., a = b; b = a;).</li><li>Fix: Break cycle by introducing registers, restructuring logic, or making assignments mutually exclusive.</li></ul><h3 id="combinational-loops-comb-loop-conditional-safe-—-cycle-within-mutually-exclusive-branches" tabindex="-1">COMBINATIONAL_LOOPS.COMB_LOOP_CONDITIONAL_SAFE — Cycle within mutually exclusive branches <a class="header-anchor" href="#combinational-loops-comb-loop-conditional-safe-—-cycle-within-mutually-exclusive-branches" aria-label="Permalink to “COMBINATIONAL_LOOPS.COMB_LOOP_CONDITIONAL_SAFE — Cycle within mutually exclusive branches”">​</a></h3><ul><li>Severity: WARN (informational, considered safe)</li><li>Note: Flow-sensitive analysis treats mutually exclusive branches as safe; verify intended behavior.</li></ul><hr><h2 id="project-imports-top-level" tabindex="-1">Project, Imports &amp; Top-level <a class="header-anchor" href="#project-imports-top-level" aria-label="Permalink to “Project, Imports &amp; Top-level”">​</a></h2><h3 id="project-and-imports-project-multiple-per-file-—-multiple-project" tabindex="-1">PROJECT_AND_IMPORTS.PROJECT_MULTIPLE_PER_FILE — Multiple @project <a class="header-anchor" href="#project-and-imports-project-multiple-per-file-—-multiple-project" aria-label="Permalink to “PROJECT_AND_IMPORTS.PROJECT_MULTIPLE_PER_FILE — Multiple @project”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Use a single @project per file.</li></ul><h3 id="project-and-imports-import-file-multiple-times-—-same-import-repeated" tabindex="-1">PROJECT_AND_IMPORTS.IMPORT_FILE_MULTIPLE_TIMES — Same import repeated <a class="header-anchor" href="#project-and-imports-import-file-multiple-times-—-same-import-repeated" aria-label="Permalink to “PROJECT_AND_IMPORTS.IMPORT_FILE_MULTIPLE_TIMES — Same import repeated”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Remove duplicate imports or normalize import graph to avoid re-importing same file.</li></ul><h3 id="project-and-imports-import-not-at-project-top-—-import-in-wrong-place" tabindex="-1">PROJECT_AND_IMPORTS.IMPORT_NOT_AT_PROJECT_TOP — @import in wrong place <a class="header-anchor" href="#project-and-imports-import-not-at-project-top-—-import-in-wrong-place" aria-label="Permalink to “PROJECT_AND_IMPORTS.IMPORT_NOT_AT_PROJECT_TOP — @import in wrong place”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Move <code>@import</code> to immediately after <code>@project</code> header, before CONFIG/CLOCKS/PIN/blackbox/top.</li></ul><h3 id="top-level-instantiation-top-port-not-listed-—-top-file-misses-a-port" tabindex="-1">TOP_LEVEL_INSTANTIATION.TOP_PORT_NOT_LISTED — Top-file misses a port <a class="header-anchor" href="#top-level-instantiation-top-port-not-listed-—-top-file-misses-a-port" aria-label="Permalink to “TOP_LEVEL_INSTANTIATION.TOP_PORT_NOT_LISTED — Top-file misses a port”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: List all module ports in <code>@top</code> mapping; specify <code>_</code> if intentionally unconnected.</li></ul><h3 id="clocks-pins-map-—-various-clock-pin-map-errors" tabindex="-1">CLOCKS_PINS_MAP.* — Various clock/pin/map errors <a class="header-anchor" href="#clocks-pins-map-—-various-clock-pin-map-errors" aria-label="Permalink to “CLOCKS_PINS_MAP.* — Various clock/pin/map errors”">​</a></h3><ul><li>Severity: ERROR/WARN depending on item (CLOCK_PORT_WIDTH_NOT_1, MAP_PIN_DECLARED_NOT_MAPPED, MAP_DUP_PHYSICAL_LOCATION, etc.)</li><li>Fix: Ensure CLOCKS entries match IN_PINS (width 1), map every declared pin in MAP, avoid mapping two logical pins to same physical pin unless tri-state intended.</li></ul><h3 id="clocks-pins-map-pin-mode-invalid-—-invalid-pin-mode-value" tabindex="-1">CLOCKS_PINS_MAP.PIN_MODE_INVALID — Invalid pin mode value <a class="header-anchor" href="#clocks-pins-map-pin-mode-invalid-—-invalid-pin-mode-value" aria-label="Permalink to “CLOCKS_PINS_MAP.PIN_MODE_INVALID — Invalid pin mode value”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: <code>mode</code> attribute is not <code>SINGLE</code> or <code>DIFFERENTIAL</code>.</li><li>Fix: Use <code>mode=SINGLE</code> or <code>mode=DIFFERENTIAL</code>.</li></ul><h3 id="clocks-pins-map-pin-mode-standard-mismatch-—-pin-mode-conflicts-with-i-o-standard" tabindex="-1">CLOCKS_PINS_MAP.PIN_MODE_STANDARD_MISMATCH — Pin mode conflicts with I/O standard <a class="header-anchor" href="#clocks-pins-map-pin-mode-standard-mismatch-—-pin-mode-conflicts-with-i-o-standard" aria-label="Permalink to “CLOCKS_PINS_MAP.PIN_MODE_STANDARD_MISMATCH — Pin mode conflicts with I/O standard”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: <code>mode=DIFFERENTIAL</code> used with a single-ended standard (e.g., LVCMOS33), or <code>mode=SINGLE</code> used with a differential standard (e.g., LVDS25).</li><li>Fix: Use a standard that matches the pin mode. Single-ended standards (LVCMOS, LVTTL, PCI33, SSTL, HSTL) require <code>mode=SINGLE</code>; differential standards (LVDS, TMDS, BLVDS, DIFF_SSTL, etc.) require <code>mode=DIFFERENTIAL</code>.</li></ul><h3 id="clocks-pins-map-pin-pull-invalid-—-invalid-pull-value" tabindex="-1">CLOCKS_PINS_MAP.PIN_PULL_INVALID — Invalid pull value <a class="header-anchor" href="#clocks-pins-map-pin-pull-invalid-—-invalid-pull-value" aria-label="Permalink to “CLOCKS_PINS_MAP.PIN_PULL_INVALID — Invalid pull value”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: <code>pull</code> attribute is not <code>UP</code>, <code>DOWN</code>, or <code>NONE</code>.</li><li>Fix: Use <code>pull=UP</code>, <code>pull=DOWN</code>, or <code>pull=NONE</code>.</li></ul><h3 id="clocks-pins-map-pin-pull-on-output-—-pull-resistor-on-output-only-pin" tabindex="-1">CLOCKS_PINS_MAP.PIN_PULL_ON_OUTPUT — Pull resistor on output-only pin <a class="header-anchor" href="#clocks-pins-map-pin-pull-on-output-—-pull-resistor-on-output-only-pin" aria-label="Permalink to “CLOCKS_PINS_MAP.PIN_PULL_ON_OUTPUT — Pull resistor on output-only pin”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: <code>pull=UP</code> or <code>pull=DOWN</code> specified on an <code>OUT_PINS</code> entry.</li><li>Fix: Remove pull attribute from output pins. Pull resistors are only meaningful on input or bidirectional pins.</li></ul><h3 id="clocks-pins-map-pin-term-invalid-—-invalid-termination-value" tabindex="-1">CLOCKS_PINS_MAP.PIN_TERM_INVALID — Invalid termination value <a class="header-anchor" href="#clocks-pins-map-pin-term-invalid-—-invalid-termination-value" aria-label="Permalink to “CLOCKS_PINS_MAP.PIN_TERM_INVALID — Invalid termination value”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: <code>term</code> attribute is not <code>ON</code> or <code>OFF</code>.</li><li>Fix: Use <code>term=ON</code> or <code>term=OFF</code>.</li></ul><h3 id="clocks-pins-map-pin-term-invalid-for-standard-—-termination-not-supported-for-standard" tabindex="-1">CLOCKS_PINS_MAP.PIN_TERM_INVALID_FOR_STANDARD — Termination not supported for standard <a class="header-anchor" href="#clocks-pins-map-pin-term-invalid-for-standard-—-termination-not-supported-for-standard" aria-label="Permalink to “CLOCKS_PINS_MAP.PIN_TERM_INVALID_FOR_STANDARD — Termination not supported for standard”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: <code>term=ON</code> used with a standard that does not support on-die termination (e.g., LVCMOS33, LVTTL, PCI33).</li><li>Fix: Termination is only valid for <code>mode=DIFFERENTIAL</code> pins or for single-ended SSTL/HSTL standards. Remove <code>term=ON</code> or change to a termination-capable standard.</li></ul><h3 id="clocks-pins-map-map-diff-expected-pair-—-differential-pin-needs-p-n-map-syntax" tabindex="-1">CLOCKS_PINS_MAP.MAP_DIFF_EXPECTED_PAIR — Differential pin needs P, N MAP syntax <a class="header-anchor" href="#clocks-pins-map-map-diff-expected-pair-—-differential-pin-needs-p-n-map-syntax" aria-label="Permalink to “CLOCKS_PINS_MAP.MAP_DIFF_EXPECTED_PAIR — Differential pin needs P, N MAP syntax”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: A pin declared with <code>mode=DIFFERENTIAL</code> is mapped with a scalar value instead of the <code>{ P=pin, N=pin }</code> pair syntax.</li><li>Fix: Use differential MAP syntax: <code>pin = { P=33, N=34 };</code></li></ul><h3 id="clocks-pins-map-map-single-unexpected-pair-—-single-ended-pin-must-not-use-p-n-pair" tabindex="-1">CLOCKS_PINS_MAP.MAP_SINGLE_UNEXPECTED_PAIR — Single-ended pin must not use P, N pair <a class="header-anchor" href="#clocks-pins-map-map-single-unexpected-pair-—-single-ended-pin-must-not-use-p-n-pair" aria-label="Permalink to “CLOCKS_PINS_MAP.MAP_SINGLE_UNEXPECTED_PAIR — Single-ended pin must not use P, N pair”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: A single-ended pin is mapped with <code>{ P=pin, N=pin }</code> pair syntax instead of a scalar value.</li><li>Fix: Use scalar MAP syntax: <code>pin = 33;</code></li></ul><h3 id="clocks-pins-map-map-diff-missing-pn-—-differential-map-missing-p-or-n" tabindex="-1">CLOCKS_PINS_MAP.MAP_DIFF_MISSING_PN — Differential MAP missing P or N <a class="header-anchor" href="#clocks-pins-map-map-diff-missing-pn-—-differential-map-missing-p-or-n" aria-label="Permalink to “CLOCKS_PINS_MAP.MAP_DIFF_MISSING_PN — Differential MAP missing P or N”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Differential MAP entry is missing the <code>P</code> or <code>N</code> identifier.</li><li>Fix: Provide both P and N: <code>pin = { P=33, N=34 };</code></li></ul><h3 id="clocks-pins-map-map-diff-same-pin-—-p-and-n-map-to-same-physical-pin" tabindex="-1">CLOCKS_PINS_MAP.MAP_DIFF_SAME_PIN — P and N map to same physical pin <a class="header-anchor" href="#clocks-pins-map-map-diff-same-pin-—-p-and-n-map-to-same-physical-pin" aria-label="Permalink to “CLOCKS_PINS_MAP.MAP_DIFF_SAME_PIN — P and N map to same physical pin”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Both P and N in a differential MAP entry refer to the same physical pin.</li><li>Fix: Use different physical pins for P (positive) and N (negative).</li></ul><hr><h2 id="blackboxes-top-level" tabindex="-1">Blackboxes &amp; Top-level <a class="header-anchor" href="#blackboxes-top-level" aria-label="Permalink to “Blackboxes &amp; Top-level”">​</a></h2><h3 id="blackbox-rules-blackbox-body-disallowed-—-blackbox-contains-body" tabindex="-1">BLACKBOX_RULES.BLACKBOX_BODY_DISALLOWED — Blackbox contains body <a class="header-anchor" href="#blackbox-rules-blackbox-body-disallowed-—-blackbox-contains-body" aria-label="Permalink to “BLACKBOX_RULES.BLACKBOX_BODY_DISALLOWED — Blackbox contains body”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Blackboxes must declare only PORT (and optional CONST) — no wires/registers/blocks.</li></ul><h3 id="blackbox-rules-blackbox-undefined-in-new-—-unknown-blackbox-instantiation" tabindex="-1">BLACKBOX_RULES.BLACKBOX_UNDEFINED_IN_NEW — Unknown blackbox instantiation <a class="header-anchor" href="#blackbox-rules-blackbox-undefined-in-new-—-unknown-blackbox-instantiation" aria-label="Permalink to “BLACKBOX_RULES.BLACKBOX_UNDEFINED_IN_NEW — Unknown blackbox instantiation”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Declare the blackbox in the project before instantiation.</li></ul><h3 id="blackbox-rules-blackbox-override-unchecked-—-override-unvalidated" tabindex="-1">BLACKBOX_RULES.BLACKBOX_OVERRIDE_UNCHECKED — OVERRIDE unvalidated <a class="header-anchor" href="#blackbox-rules-blackbox-override-unchecked-—-override-unvalidated" aria-label="Permalink to “BLACKBOX_RULES.BLACKBOX_OVERRIDE_UNCHECKED — OVERRIDE unvalidated”">​</a></h3><ul><li>Severity: INFO</li><li>Note: OVERRIDE values are passed through to vendor IP; tool cannot validate them.</li></ul><hr><h2 id="mem-memory-—-declaration-access" tabindex="-1">MEM (Memory) — Declaration &amp; Access <a class="header-anchor" href="#mem-memory-—-declaration-access" aria-label="Permalink to “MEM (Memory) — Declaration &amp; Access”">​</a></h2><h3 id="mem-declaration-mem-undefined-name-—-memory-not-declared" tabindex="-1">MEM_DECLARATION.MEM_UNDEFINED_NAME — Memory not declared <a class="header-anchor" href="#mem-declaration-mem-undefined-name-—-memory-not-declared" aria-label="Permalink to “MEM_DECLARATION.MEM_UNDEFINED_NAME — Memory not declared”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Declare MEM block before using <code>mem.port[addr]</code> access.</li></ul><h3 id="mem-declaration-mem-invalid-word-width-mem-invalid-depth-—-word-width-or-depth-invalid" tabindex="-1">MEM_DECLARATION.MEM_INVALID_WORD_WIDTH / MEM_INVALID_DEPTH — Word width or depth invalid <a class="header-anchor" href="#mem-declaration-mem-invalid-word-width-mem-invalid-depth-—-word-width-or-depth-invalid" aria-label="Permalink to “MEM_DECLARATION.MEM_INVALID_WORD_WIDTH / MEM_INVALID_DEPTH — Word width or depth invalid”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Use positive integer or valid CONST resolving to positive integer.</li></ul><h3 id="mem-declaration-mem-init-contains-x-mem-init-literal-overflow-mem-init-file-too-large-—-init-problems" tabindex="-1">MEM_DECLARATION.MEM_INIT_CONTAINS_X / MEM_INIT_LITERAL_OVERFLOW / MEM_INIT_FILE_TOO_LARGE — Init problems <a class="header-anchor" href="#mem-declaration-mem-init-contains-x-mem-init-literal-overflow-mem-init-file-too-large-—-init-problems" aria-label="Permalink to “MEM_DECLARATION.MEM_INIT_CONTAINS_X / MEM_INIT_LITERAL_OVERFLOW / MEM_INIT_FILE_TOO_LARGE — Init problems”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Ensure MEM init literal contains only 0/1 (no <code>x</code>), fits word width; ensure init file length ≤ depth × word_width.</li></ul><h3 id="mem-declaration-mem-empty-port-list-—-mem-without-ports" tabindex="-1">MEM_DECLARATION.MEM_EMPTY_PORT_LIST — MEM without ports <a class="header-anchor" href="#mem-declaration-mem-empty-port-list-—-mem-without-ports" aria-label="Permalink to “MEM_DECLARATION.MEM_EMPTY_PORT_LIST — MEM without ports”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Declare at least one OUT or IN port.</li></ul><h3 id="mem-access-mem-port-undefined-—-port-name-not-declared-in-mem" tabindex="-1">MEM_ACCESS.MEM_PORT_UNDEFINED — Port name not declared in MEM <a class="header-anchor" href="#mem-access-mem-port-undefined-—-port-name-not-declared-in-mem" aria-label="Permalink to “MEM_ACCESS.MEM_PORT_UNDEFINED — Port name not declared in MEM”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Use declared MEM port names.</li></ul><h3 id="mem-access-mem-read-sync-with-equals-—-sync-read-used-with-instead-of" tabindex="-1">MEM_ACCESS.MEM_READ_SYNC_WITH_EQUALS — Sync read used with <code>=</code> instead of <code>&lt;=</code> <a class="header-anchor" href="#mem-access-mem-read-sync-with-equals-—-sync-read-used-with-instead-of" aria-label="Permalink to “MEM_ACCESS.MEM_READ_SYNC_WITH_EQUALS — Sync read used with = instead of &lt;=”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Use <code>&lt;=</code> in SYNCHRONOUS block for synchronous reads.</li></ul><h3 id="mem-access-mem-write-in-async-block-—-write-used-in-asynchronous" tabindex="-1">MEM_ACCESS.MEM_WRITE_IN_ASYNC_BLOCK — Write used in ASYNCHRONOUS <a class="header-anchor" href="#mem-access-mem-write-in-async-block-—-write-used-in-asynchronous" aria-label="Permalink to “MEM_ACCESS.MEM_WRITE_IN_ASYNC_BLOCK — Write used in ASYNCHRONOUS”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Perform writes in SYNCHRONOUS blocks only.</li></ul><h3 id="mem-access-mem-addr-width-too-wide-mem-const-addr-out-of-range-—-address-width-const-address-out-of-range" tabindex="-1">MEM_ACCESS.MEM_ADDR_WIDTH_TOO_WIDE / MEM_CONST_ADDR_OUT_OF_RANGE — Address width / const address out-of-range <a class="header-anchor" href="#mem-access-mem-addr-width-too-wide-mem-const-addr-out-of-range-—-address-width-const-address-out-of-range" aria-label="Permalink to “MEM_ACCESS.MEM_ADDR_WIDTH_TOO_WIDE / MEM_CONST_ADDR_OUT_OF_RANGE — Address width / const address out-of-range”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Use address width ≤ ceil(log2(depth)); ensure constant addresses &lt; depth.</li></ul><h3 id="mem-access-mem-multiple-writes-same-in-—-multiple-writes-to-same-in-port-in-one-block" tabindex="-1">MEM_ACCESS.MEM_MULTIPLE_WRITES_SAME_IN — Multiple writes to same IN port in one block <a class="header-anchor" href="#mem-access-mem-multiple-writes-same-in-—-multiple-writes-to-same-in-port-in-one-block" aria-label="Permalink to “MEM_ACCESS.MEM_MULTIPLE_WRITES_SAME_IN — Multiple writes to same IN port in one block”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Ensure only one write to each IN port per SYNCHRONOUS block per execution path (use conditional exclusivity).</li></ul><h3 id="mem-access-mem-invalid-write-mode-—-unknown-write-mode" tabindex="-1">MEM_ACCESS.MEM_INVALID_WRITE_MODE — Unknown write mode <a class="header-anchor" href="#mem-access-mem-invalid-write-mode-—-unknown-write-mode" aria-label="Permalink to “MEM_ACCESS.MEM_INVALID_WRITE_MODE — Unknown write mode”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Use WRITE_FIRST, READ_FIRST, or NO_CHANGE.</li></ul><h3 id="mem-access-mem-inout-indexed-—-inout-port-indexed" tabindex="-1">MEM_ACCESS.MEM_INOUT_INDEXED — INOUT port indexed <a class="header-anchor" href="#mem-access-mem-inout-indexed-—-inout-port-indexed" aria-label="Permalink to “MEM_ACCESS.MEM_INOUT_INDEXED — INOUT port indexed”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: INOUT ports may not use <code>mem.port[addr]</code> syntax; use <code>.addr</code>/<code>.data</code>/<code>.wdata</code> pseudo-fields.</li></ul><h3 id="mem-access-mem-inout-wdata-in-async-—-inout-wdata-in-asynchronous" tabindex="-1">MEM_ACCESS.MEM_INOUT_WDATA_IN_ASYNC — INOUT .wdata in ASYNCHRONOUS <a class="header-anchor" href="#mem-access-mem-inout-wdata-in-async-—-inout-wdata-in-asynchronous" aria-label="Permalink to “MEM_ACCESS.MEM_INOUT_WDATA_IN_ASYNC — INOUT .wdata in ASYNCHRONOUS”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: INOUT port <code>.wdata</code> may only be assigned in SYNCHRONOUS blocks.</li></ul><h3 id="mem-access-mem-inout-addr-in-async-—-inout-addr-in-asynchronous" tabindex="-1">MEM_ACCESS.MEM_INOUT_ADDR_IN_ASYNC — INOUT .addr in ASYNCHRONOUS <a class="header-anchor" href="#mem-access-mem-inout-addr-in-async-—-inout-addr-in-asynchronous" aria-label="Permalink to “MEM_ACCESS.MEM_INOUT_ADDR_IN_ASYNC — INOUT .addr in ASYNCHRONOUS”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: INOUT port <code>.addr</code> may only be assigned in SYNCHRONOUS blocks.</li></ul><h3 id="mem-access-mem-inout-wdata-wrong-op-—-inout-wdata-wrong-operator" tabindex="-1">MEM_ACCESS.MEM_INOUT_WDATA_WRONG_OP — INOUT .wdata wrong operator <a class="header-anchor" href="#mem-access-mem-inout-wdata-wrong-op-—-inout-wdata-wrong-operator" aria-label="Permalink to “MEM_ACCESS.MEM_INOUT_WDATA_WRONG_OP — INOUT .wdata wrong operator”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: INOUT port <code>.wdata</code> must be assigned with <code>&lt;=</code> operator.</li></ul><h3 id="mem-access-mem-multiple-addr-assigns-—-multiple-inout-addr-assignments" tabindex="-1">MEM_ACCESS.MEM_MULTIPLE_ADDR_ASSIGNS — Multiple INOUT .addr assignments <a class="header-anchor" href="#mem-access-mem-multiple-addr-assigns-—-multiple-inout-addr-assignments" aria-label="Permalink to “MEM_ACCESS.MEM_MULTIPLE_ADDR_ASSIGNS — Multiple INOUT .addr assignments”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Assign <code>.addr</code> at most once per execution path.</li></ul><h3 id="mem-access-mem-multiple-wdata-assigns-—-multiple-inout-wdata-assignments" tabindex="-1">MEM_ACCESS.MEM_MULTIPLE_WDATA_ASSIGNS — Multiple INOUT .wdata assignments <a class="header-anchor" href="#mem-access-mem-multiple-wdata-assigns-—-multiple-inout-wdata-assignments" aria-label="Permalink to “MEM_ACCESS.MEM_MULTIPLE_WDATA_ASSIGNS — Multiple INOUT .wdata assignments”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Assign <code>.wdata</code> at most once per execution path.</li></ul><h3 id="mem-declaration-mem-inout-mixed-with-in-out-—-inout-mixed-with-in-out" tabindex="-1">MEM_DECLARATION.MEM_INOUT_MIXED_WITH_IN_OUT — INOUT mixed with IN/OUT <a class="header-anchor" href="#mem-declaration-mem-inout-mixed-with-in-out-—-inout-mixed-with-in-out" aria-label="Permalink to “MEM_DECLARATION.MEM_INOUT_MIXED_WITH_IN_OUT — INOUT mixed with IN/OUT”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: INOUT ports cannot be mixed with IN or OUT ports in the same MEM declaration.</li></ul><h3 id="mem-declaration-mem-inout-async-—-inout-with-async-keyword" tabindex="-1">MEM_DECLARATION.MEM_INOUT_ASYNC — INOUT with ASYNC keyword <a class="header-anchor" href="#mem-declaration-mem-inout-async-—-inout-with-async-keyword" aria-label="Permalink to “MEM_DECLARATION.MEM_INOUT_ASYNC — INOUT with ASYNC keyword”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: INOUT ports are always synchronous; do not specify ASYNC/SYNC keyword.</li></ul><h3 id="mem-warnings-mem-warn-port-never-accessed-—-mem-port-unused" tabindex="-1">MEM_WARNINGS.MEM_WARN_PORT_NEVER_ACCESSED — MEM port unused <a class="header-anchor" href="#mem-warnings-mem-warn-port-never-accessed-—-mem-port-unused" aria-label="Permalink to “MEM_WARNINGS.MEM_WARN_PORT_NEVER_ACCESSED — MEM port unused”">​</a></h3><ul><li>Severity: WARN</li><li>Fix: Remove unused port or add intended accesses.</li></ul><h3 id="mem-warnings-mem-warn-partial-init-—-init-file-smaller-than-depth" tabindex="-1">MEM_WARNINGS.MEM_WARN_PARTIAL_INIT — Init file smaller than depth <a class="header-anchor" href="#mem-warnings-mem-warn-partial-init-—-init-file-smaller-than-depth" aria-label="Permalink to “MEM_WARNINGS.MEM_WARN_PARTIAL_INIT — Init file smaller than depth”">​</a></h3><ul><li>Severity: WARN</li><li>Fix: Provide full init file or accept zero-padding.</li></ul><hr><h2 id="general-warnings-info" tabindex="-1">General Warnings &amp; Info <a class="header-anchor" href="#general-warnings-info" aria-label="Permalink to “General Warnings &amp; Info”">​</a></h2><h3 id="general-warnings-warn-unused-register-—-unused-register" tabindex="-1">GENERAL_WARNINGS.WARN_UNUSED_REGISTER — Unused register <a class="header-anchor" href="#general-warnings-warn-unused-register-—-unused-register" aria-label="Permalink to “GENERAL_WARNINGS.WARN_UNUSED_REGISTER — Unused register”">​</a></h3><ul><li>Severity: WARN</li><li>Fix: Remove register if not needed or use it in logic.</li></ul><h3 id="general-warnings-warn-unconnected-output-—-unconnected-module-output" tabindex="-1">GENERAL_WARNINGS.WARN_UNCONNECTED_OUTPUT — Unconnected module output <a class="header-anchor" href="#general-warnings-warn-unconnected-output-—-unconnected-module-output" aria-label="Permalink to “GENERAL_WARNINGS.WARN_UNCONNECTED_OUTPUT — Unconnected module output”">​</a></h3><ul><li>Severity: WARN</li><li>Fix: Drive the output, connect to top-level pin, or intentionally bind to <code>_</code> and document intent.</li></ul><h3 id="general-warnings-warn-incomplete-select-async-—-async-select-missing-default" tabindex="-1">GENERAL_WARNINGS.WARN_INCOMPLETE_SELECT_ASYNC — ASYNC SELECT missing DEFAULT <a class="header-anchor" href="#general-warnings-warn-incomplete-select-async-—-async-select-missing-default" aria-label="Permalink to “GENERAL_WARNINGS.WARN_INCOMPLETE_SELECT_ASYNC — ASYNC SELECT missing DEFAULT”">​</a></h3><ul><li>Severity: WARN</li><li>Fix: Add DEFAULT to prevent floating nets.</li></ul><h3 id="general-warnings-warn-dead-code-unreachable-—-unreachable-statements" tabindex="-1">GENERAL_WARNINGS.WARN_DEAD_CODE_UNREACHABLE — Unreachable statements <a class="header-anchor" href="#general-warnings-warn-dead-code-unreachable-—-unreachable-statements" aria-label="Permalink to “GENERAL_WARNINGS.WARN_DEAD_CODE_UNREACHABLE — Unreachable statements”">​</a></h3><ul><li>Severity: WARN</li><li>Fix: Remove or correct unreachable logic conditions.</li></ul><h3 id="general-warnings-warn-unused-module-—-module-never-instantiated" tabindex="-1">GENERAL_WARNINGS.WARN_UNUSED_MODULE — Module never instantiated <a class="header-anchor" href="#general-warnings-warn-unused-module-—-module-never-instantiated" aria-label="Permalink to “GENERAL_WARNINGS.WARN_UNUSED_MODULE — Module never instantiated”">​</a></h3><ul><li>Severity: WARN</li><li>Fix: Instantiate module or remove it.</li></ul><h3 id="general-warnings-warn-unsinked-register-—-register-written-but-never-read" tabindex="-1">GENERAL_WARNINGS.WARN_UNSINKED_REGISTER — Register written but never read <a class="header-anchor" href="#general-warnings-warn-unsinked-register-—-register-written-but-never-read" aria-label="Permalink to “GENERAL_WARNINGS.WARN_UNSINKED_REGISTER — Register written but never read”">​</a></h3><ul><li>Severity: WARN</li><li>Fix: Read the register value or remove it if not needed.</li></ul><h3 id="general-warnings-warn-undriven-register-—-register-read-but-never-written" tabindex="-1">GENERAL_WARNINGS.WARN_UNDRIVEN_REGISTER — Register read but never written <a class="header-anchor" href="#general-warnings-warn-undriven-register-—-register-read-but-never-written" aria-label="Permalink to “GENERAL_WARNINGS.WARN_UNDRIVEN_REGISTER — Register read but never written”">​</a></h3><ul><li>Severity: WARN</li><li>Fix: Assign the register in a SYNCHRONOUS block.</li></ul><h3 id="general-warnings-warn-unused-wire-—-wire-never-driven-or-read" tabindex="-1">GENERAL_WARNINGS.WARN_UNUSED_WIRE — Wire never driven or read <a class="header-anchor" href="#general-warnings-warn-unused-wire-—-wire-never-driven-or-read" aria-label="Permalink to “GENERAL_WARNINGS.WARN_UNUSED_WIRE — Wire never driven or read”">​</a></h3><ul><li>Severity: WARN</li><li>Fix: Remove unused wire declaration.</li></ul><h3 id="general-warnings-warn-unused-port-—-port-never-used" tabindex="-1">GENERAL_WARNINGS.WARN_UNUSED_PORT — Port never used <a class="header-anchor" href="#general-warnings-warn-unused-port-—-port-never-used" aria-label="Permalink to “GENERAL_WARNINGS.WARN_UNUSED_PORT — Port never used”">​</a></h3><ul><li>Severity: WARN</li><li>Fix: Remove unused port or connect it.</li></ul><h3 id="general-warnings-warn-internal-tristate-—-internal-tri-state-not-fpga-compatible" tabindex="-1">GENERAL_WARNINGS.WARN_INTERNAL_TRISTATE — Internal tri-state not FPGA-compatible <a class="header-anchor" href="#general-warnings-warn-internal-tristate-—-internal-tri-state-not-fpga-compatible" aria-label="Permalink to “GENERAL_WARNINGS.WARN_INTERNAL_TRISTATE — Internal tri-state not FPGA-compatible”">​</a></h3><ul><li>Severity: WARN</li><li>Cause: Internal tri-state logic is not supported by most FPGAs.</li><li>Fix: Use <code>--tristate-default</code> to enable automatic tri-state elimination.</li></ul><hr><h2 id="latch-rules" tabindex="-1">Latch Rules <a class="header-anchor" href="#latch-rules" aria-label="Permalink to “Latch Rules”">​</a></h2><h3 id="latch-rules-latch-assign-non-guarded-—-latch-assignment-not-guarded" tabindex="-1">LATCH_RULES.LATCH_ASSIGN_NON_GUARDED — Latch assignment not guarded <a class="header-anchor" href="#latch-rules-latch-assign-non-guarded-—-latch-assignment-not-guarded" aria-label="Permalink to “LATCH_RULES.LATCH_ASSIGN_NON_GUARDED — Latch assignment not guarded”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: LATCH must be written via guarded assignment <code>name &lt;= enable : data;</code> in ASYNCHRONOUS blocks.</li><li>Fix: Use guarded syntax for D latches or <code>name &lt;= set : reset;</code> for SR latches.</li></ul><h3 id="latch-rules-latch-assign-in-sync-—-latch-written-in-synchronous" tabindex="-1">LATCH_RULES.LATCH_ASSIGN_IN_SYNC — Latch written in SYNCHRONOUS <a class="header-anchor" href="#latch-rules-latch-assign-in-sync-—-latch-written-in-synchronous" aria-label="Permalink to “LATCH_RULES.LATCH_ASSIGN_IN_SYNC — Latch written in SYNCHRONOUS”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Move latch assignments to ASYNCHRONOUS blocks; use REGISTER for edge-triggered storage.</li></ul><h3 id="latch-rules-latch-enable-width-not-1-—-d-latch-enable-not-width-1" tabindex="-1">LATCH_RULES.LATCH_ENABLE_WIDTH_NOT_1 — D-latch enable not width-1 <a class="header-anchor" href="#latch-rules-latch-enable-width-not-1-—-d-latch-enable-not-width-1" aria-label="Permalink to “LATCH_RULES.LATCH_ENABLE_WIDTH_NOT_1 — D-latch enable not width-1”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Enable expression must have width [1].</li></ul><h3 id="latch-rules-latch-alias-forbidden-—-latch-aliased" tabindex="-1">LATCH_RULES.LATCH_ALIAS_FORBIDDEN — Latch aliased <a class="header-anchor" href="#latch-rules-latch-alias-forbidden-—-latch-aliased" aria-label="Permalink to “LATCH_RULES.LATCH_ALIAS_FORBIDDEN — Latch aliased”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Latches may not be aliased using <code>=</code>; they must not be merged into other nets.</li></ul><h3 id="latch-rules-latch-invalid-type-—-invalid-latch-type" tabindex="-1">LATCH_RULES.LATCH_INVALID_TYPE — Invalid latch type <a class="header-anchor" href="#latch-rules-latch-invalid-type-—-invalid-latch-type" aria-label="Permalink to “LATCH_RULES.LATCH_INVALID_TYPE — Invalid latch type”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: LATCH type must be <code>D</code> or <code>SR</code>.</li></ul><h3 id="latch-rules-latch-width-invalid-—-invalid-latch-width" tabindex="-1">LATCH_RULES.LATCH_WIDTH_INVALID — Invalid latch width <a class="header-anchor" href="#latch-rules-latch-width-invalid-—-invalid-latch-width" aria-label="Permalink to “LATCH_RULES.LATCH_WIDTH_INVALID — Invalid latch width”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Width must be a positive integer.</li></ul><h3 id="latch-rules-latch-sr-width-mismatch-—-sr-latch-set-reset-width-mismatch" tabindex="-1">LATCH_RULES.LATCH_SR_WIDTH_MISMATCH — SR latch set/reset width mismatch <a class="header-anchor" href="#latch-rules-latch-sr-width-mismatch-—-sr-latch-set-reset-width-mismatch" aria-label="Permalink to “LATCH_RULES.LATCH_SR_WIDTH_MISMATCH — SR latch set/reset width mismatch”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Set and reset expression widths must match the latch width.</li></ul><h3 id="latch-rules-latch-as-clock-or-cdc-—-latch-used-as-clock-or-cdc-source" tabindex="-1">LATCH_RULES.LATCH_AS_CLOCK_OR_CDC — Latch used as clock or CDC source <a class="header-anchor" href="#latch-rules-latch-as-clock-or-cdc-—-latch-used-as-clock-or-cdc-source" aria-label="Permalink to “LATCH_RULES.LATCH_AS_CLOCK_OR_CDC — Latch used as clock or CDC source”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Latches may not be used as clock signals or in CDC declarations.</li></ul><h3 id="latch-rules-latch-in-const-context-—-latch-in-compile-time-context" tabindex="-1">LATCH_RULES.LATCH_IN_CONST_CONTEXT — Latch in compile-time context <a class="header-anchor" href="#latch-rules-latch-in-const-context-—-latch-in-compile-time-context" aria-label="Permalink to “LATCH_RULES.LATCH_IN_CONST_CONTEXT — Latch in compile-time context”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Latch identifiers may not appear in <code>@check</code>/<code>@feature</code> conditions.</li></ul><h3 id="latch-rules-latch-chip-unsupported-—-latch-not-supported-by-chip" tabindex="-1">LATCH_RULES.LATCH_CHIP_UNSUPPORTED — Latch not supported by chip <a class="header-anchor" href="#latch-rules-latch-chip-unsupported-—-latch-not-supported-by-chip" aria-label="Permalink to “LATCH_RULES.LATCH_CHIP_UNSUPPORTED — Latch not supported by chip”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Selected chip does not support the latch type.</li></ul><hr><h2 id="template-rules" tabindex="-1">Template Rules <a class="header-anchor" href="#template-rules" aria-label="Permalink to “Template Rules”">​</a></h2><h3 id="template-template-undefined-—-undefined-template" tabindex="-1">TEMPLATE.TEMPLATE_UNDEFINED — Undefined template <a class="header-anchor" href="#template-template-undefined-—-undefined-template" aria-label="Permalink to “TEMPLATE.TEMPLATE_UNDEFINED — Undefined template”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Ensure the template is defined before <code>@apply</code>.</li></ul><h3 id="template-template-arg-count-mismatch-—-argument-count-mismatch" tabindex="-1">TEMPLATE.TEMPLATE_ARG_COUNT_MISMATCH — Argument count mismatch <a class="header-anchor" href="#template-template-arg-count-mismatch-—-argument-count-mismatch" aria-label="Permalink to “TEMPLATE.TEMPLATE_ARG_COUNT_MISMATCH — Argument count mismatch”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: <code>@apply</code> argument count must match template parameter count.</li></ul><h3 id="template-template-count-not-nonneg-int-—-invalid-apply-count" tabindex="-1">TEMPLATE.TEMPLATE_COUNT_NOT_NONNEG_INT — Invalid @apply count <a class="header-anchor" href="#template-template-count-not-nonneg-int-—-invalid-apply-count" aria-label="Permalink to “TEMPLATE.TEMPLATE_COUNT_NOT_NONNEG_INT — Invalid @apply count”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Count must resolve to a non-negative integer.</li></ul><h3 id="template-template-nested-def-—-nested-template-definition" tabindex="-1">TEMPLATE.TEMPLATE_NESTED_DEF — Nested template definition <a class="header-anchor" href="#template-template-nested-def-—-nested-template-definition" aria-label="Permalink to “TEMPLATE.TEMPLATE_NESTED_DEF — Nested template definition”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: <code>@template</code> definitions may not be nested.</li></ul><h3 id="template-template-forbidden-decl-—-declaration-inside-template" tabindex="-1">TEMPLATE.TEMPLATE_FORBIDDEN_DECL — Declaration inside template <a class="header-anchor" href="#template-template-forbidden-decl-—-declaration-inside-template" aria-label="Permalink to “TEMPLATE.TEMPLATE_FORBIDDEN_DECL — Declaration inside template”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Use <code>@scratch</code> for temporary signals; WIRE/REGISTER/PORT/CONST/MEM/MUX are forbidden.</li></ul><h3 id="template-template-forbidden-block-header-—-block-header-inside-template" tabindex="-1">TEMPLATE.TEMPLATE_FORBIDDEN_BLOCK_HEADER — Block header inside template <a class="header-anchor" href="#template-template-forbidden-block-header-—-block-header-inside-template" aria-label="Permalink to “TEMPLATE.TEMPLATE_FORBIDDEN_BLOCK_HEADER — Block header inside template”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: SYNCHRONOUS/ASYNCHRONOUS block headers are not allowed in template body.</li></ul><h3 id="template-template-forbidden-directive-—-directive-inside-template" tabindex="-1">TEMPLATE.TEMPLATE_FORBIDDEN_DIRECTIVE — Directive inside template <a class="header-anchor" href="#template-template-forbidden-directive-—-directive-inside-template" aria-label="Permalink to “TEMPLATE.TEMPLATE_FORBIDDEN_DIRECTIVE — Directive inside template”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: @new/@module/@feature and other structural directives are forbidden.</li></ul><h3 id="template-template-scratch-outside-—-scratch-outside-template" tabindex="-1">TEMPLATE.TEMPLATE_SCRATCH_OUTSIDE — @scratch outside template <a class="header-anchor" href="#template-template-scratch-outside-—-scratch-outside-template" aria-label="Permalink to “TEMPLATE.TEMPLATE_SCRATCH_OUTSIDE — @scratch outside template”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: <code>@scratch</code> may only appear inside a <code>@template</code> body.</li></ul><h3 id="template-template-apply-outside-block-—-apply-outside-block" tabindex="-1">TEMPLATE.TEMPLATE_APPLY_OUTSIDE_BLOCK — @apply outside block <a class="header-anchor" href="#template-template-apply-outside-block-—-apply-outside-block" aria-label="Permalink to “TEMPLATE.TEMPLATE_APPLY_OUTSIDE_BLOCK — @apply outside block”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: <code>@apply</code> may only appear inside ASYNCHRONOUS or SYNCHRONOUS blocks.</li></ul><h3 id="template-template-dup-name-—-duplicate-template-name" tabindex="-1">TEMPLATE.TEMPLATE_DUP_NAME — Duplicate template name <a class="header-anchor" href="#template-template-dup-name-—-duplicate-template-name" aria-label="Permalink to “TEMPLATE.TEMPLATE_DUP_NAME — Duplicate template name”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Template names must be unique within the same scope.</li></ul><h3 id="template-template-dup-param-—-duplicate-parameter-name" tabindex="-1">TEMPLATE.TEMPLATE_DUP_PARAM — Duplicate parameter name <a class="header-anchor" href="#template-template-dup-param-—-duplicate-parameter-name" aria-label="Permalink to “TEMPLATE.TEMPLATE_DUP_PARAM — Duplicate parameter name”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Parameter names must be unique within the template definition.</li></ul><h3 id="template-template-scratch-width-invalid-—-invalid-scratch-width" tabindex="-1">TEMPLATE.TEMPLATE_SCRATCH_WIDTH_INVALID — Invalid @scratch width <a class="header-anchor" href="#template-template-scratch-width-invalid-—-invalid-scratch-width" aria-label="Permalink to “TEMPLATE.TEMPLATE_SCRATCH_WIDTH_INVALID — Invalid @scratch width”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Width must be a positive integer constant expression.</li></ul><h3 id="template-template-external-ref-—-external-reference-in-template" tabindex="-1">TEMPLATE.TEMPLATE_EXTERNAL_REF — External reference in template <a class="header-anchor" href="#template-template-external-ref-—-external-reference-in-template" aria-label="Permalink to “TEMPLATE.TEMPLATE_EXTERNAL_REF — External reference in template”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: All identifiers must be parameters, @scratch wires, or compile-time constants. Pass external signals as arguments.</li></ul><hr><h2 id="feature-guard-rules" tabindex="-1">Feature Guard Rules <a class="header-anchor" href="#feature-guard-rules" aria-label="Permalink to “Feature Guard Rules”">​</a></h2><h3 id="feature-guards-feature-cond-width-not-1-—-feature-condition-not-width-1" tabindex="-1">FEATURE_GUARDS.FEATURE_COND_WIDTH_NOT_1 — Feature condition not width-1 <a class="header-anchor" href="#feature-guards-feature-cond-width-not-1-—-feature-condition-not-width-1" aria-label="Permalink to “FEATURE_GUARDS.FEATURE_COND_WIDTH_NOT_1 — Feature condition not width-1”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Feature guard condition must evaluate to a 1-bit value.</li></ul><h3 id="feature-guards-feature-expr-invalid-context-—-invalid-feature-condition" tabindex="-1">FEATURE_GUARDS.FEATURE_EXPR_INVALID_CONTEXT — Invalid feature condition <a class="header-anchor" href="#feature-guards-feature-expr-invalid-context-—-invalid-feature-condition" aria-label="Permalink to “FEATURE_GUARDS.FEATURE_EXPR_INVALID_CONTEXT — Invalid feature condition”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Feature guard condition may only reference CONFIG, module CONST, literals, and logical/comparison operators.</li></ul><h3 id="feature-guards-feature-nested-—-nested-feature" tabindex="-1">FEATURE_GUARDS.FEATURE_NESTED — Nested @feature <a class="header-anchor" href="#feature-guards-feature-nested-—-nested-feature" aria-label="Permalink to “FEATURE_GUARDS.FEATURE_NESTED — Nested @feature”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: @feature guards may not be nested inside other @feature guards.</li></ul><h3 id="feature-guards-feature-validation-both-paths-—-both-paths-must-validate" tabindex="-1">FEATURE_GUARDS.FEATURE_VALIDATION_BOTH_PATHS — Both paths must validate <a class="header-anchor" href="#feature-guards-feature-validation-both-paths-—-both-paths-must-validate" aria-label="Permalink to “FEATURE_GUARDS.FEATURE_VALIDATION_BOTH_PATHS — Both paths must validate”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Both the enabled and disabled branches must pass full semantic validation.</li></ul><hr><h2 id="check-rules" tabindex="-1">@check Rules <a class="header-anchor" href="#check-rules" aria-label="Permalink to “@check Rules”">​</a></h2><h3 id="check-rules-check-failed-—-compile-time-assertion-failed" tabindex="-1">CHECK_RULES.CHECK_FAILED — Compile-time assertion failed <a class="header-anchor" href="#check-rules-check-failed-—-compile-time-assertion-failed" aria-label="Permalink to “CHECK_RULES.CHECK_FAILED — Compile-time assertion failed”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: <code>@check</code> expression evaluated to zero.</li><li>Fix: Correct the assertion condition or the values it depends on.</li></ul><h3 id="check-rules-check-invalid-expr-type-—-invalid-check-expression" tabindex="-1">CHECK_RULES.CHECK_INVALID_EXPR_TYPE — Invalid @check expression <a class="header-anchor" href="#check-rules-check-invalid-expr-type-—-invalid-check-expression" aria-label="Permalink to “CHECK_RULES.CHECK_INVALID_EXPR_TYPE — Invalid @check expression”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Expression must be a nonnegative integer constant over literals, CONST, and CONFIG.</li></ul><h3 id="check-rules-check-invalid-placement-—-check-in-invalid-location" tabindex="-1">CHECK_RULES.CHECK_INVALID_PLACEMENT — @check in invalid location <a class="header-anchor" href="#check-rules-check-invalid-placement-—-check-in-invalid-location" aria-label="Permalink to “CHECK_RULES.CHECK_INVALID_PLACEMENT — @check in invalid location”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: @check may not appear inside conditional or @feature bodies.</li></ul><hr><h2 id="bus-rules" tabindex="-1">BUS Rules <a class="header-anchor" href="#bus-rules" aria-label="Permalink to “BUS Rules”">​</a></h2><h3 id="bus-rules-bus-def-dup-name-—-duplicate-bus-definition" tabindex="-1">BUS_RULES.BUS_DEF_DUP_NAME — Duplicate BUS definition <a class="header-anchor" href="#bus-rules-bus-def-dup-name-—-duplicate-bus-definition" aria-label="Permalink to “BUS_RULES.BUS_DEF_DUP_NAME — Duplicate BUS definition”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: BUS definition names must be unique within the project.</li></ul><h3 id="bus-rules-bus-def-signal-dup-name-—-duplicate-bus-signal-name" tabindex="-1">BUS_RULES.BUS_DEF_SIGNAL_DUP_NAME — Duplicate BUS signal name <a class="header-anchor" href="#bus-rules-bus-def-signal-dup-name-—-duplicate-bus-signal-name" aria-label="Permalink to “BUS_RULES.BUS_DEF_SIGNAL_DUP_NAME — Duplicate BUS signal name”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Signal names within a BUS definition must be unique.</li></ul><h3 id="bus-rules-bus-def-invalid-dir-—-invalid-bus-signal-direction" tabindex="-1">BUS_RULES.BUS_DEF_INVALID_DIR — Invalid BUS signal direction <a class="header-anchor" href="#bus-rules-bus-def-invalid-dir-—-invalid-bus-signal-direction" aria-label="Permalink to “BUS_RULES.BUS_DEF_INVALID_DIR — Invalid BUS signal direction”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Direction must be IN, OUT, or INOUT.</li></ul><h3 id="bus-rules-bus-port-unknown-bus-—-unknown-bus-reference" tabindex="-1">BUS_RULES.BUS_PORT_UNKNOWN_BUS — Unknown BUS reference <a class="header-anchor" href="#bus-rules-bus-port-unknown-bus-—-unknown-bus-reference" aria-label="Permalink to “BUS_RULES.BUS_PORT_UNKNOWN_BUS — Unknown BUS reference”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: BUS port references a BUS name not declared in the project.</li></ul><h3 id="bus-rules-bus-port-invalid-role-—-invalid-bus-role" tabindex="-1">BUS_RULES.BUS_PORT_INVALID_ROLE — Invalid BUS role <a class="header-anchor" href="#bus-rules-bus-port-invalid-role-—-invalid-bus-role" aria-label="Permalink to “BUS_RULES.BUS_PORT_INVALID_ROLE — Invalid BUS role”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Role must be SOURCE or TARGET.</li></ul><h3 id="bus-rules-bus-port-array-count-invalid-—-invalid-bus-array-count" tabindex="-1">BUS_RULES.BUS_PORT_ARRAY_COUNT_INVALID — Invalid BUS array count <a class="header-anchor" href="#bus-rules-bus-port-array-count-invalid-—-invalid-bus-array-count" aria-label="Permalink to “BUS_RULES.BUS_PORT_ARRAY_COUNT_INVALID — Invalid BUS array count”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Array count must be a positive integer constant expression.</li></ul><h3 id="bus-rules-bus-port-index-required-—-bus-index-required" tabindex="-1">BUS_RULES.BUS_PORT_INDEX_REQUIRED — BUS index required <a class="header-anchor" href="#bus-rules-bus-port-index-required-—-bus-index-required" aria-label="Permalink to “BUS_RULES.BUS_PORT_INDEX_REQUIRED — BUS index required”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Arrayed BUS access requires an explicit index or wildcard <code>[*]</code>.</li></ul><h3 id="bus-rules-bus-port-index-not-array-—-indexed-access-on-non-array-bus" tabindex="-1">BUS_RULES.BUS_PORT_INDEX_NOT_ARRAY — Indexed access on non-array BUS <a class="header-anchor" href="#bus-rules-bus-port-index-not-array-—-indexed-access-on-non-array-bus" aria-label="Permalink to “BUS_RULES.BUS_PORT_INDEX_NOT_ARRAY — Indexed access on non-array BUS”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Only arrayed BUS ports support indexed access.</li></ul><h3 id="bus-rules-bus-port-index-out-of-range-—-bus-index-out-of-range" tabindex="-1">BUS_RULES.BUS_PORT_INDEX_OUT_OF_RANGE — BUS index out of range <a class="header-anchor" href="#bus-rules-bus-port-index-out-of-range-—-bus-index-out-of-range" aria-label="Permalink to “BUS_RULES.BUS_PORT_INDEX_OUT_OF_RANGE — BUS index out of range”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Index must be within [0, count-1].</li></ul><h3 id="bus-rules-bus-port-not-bus-—-member-access-on-non-bus-port" tabindex="-1">BUS_RULES.BUS_PORT_NOT_BUS — Member access on non-BUS port <a class="header-anchor" href="#bus-rules-bus-port-not-bus-—-member-access-on-non-bus-port" aria-label="Permalink to “BUS_RULES.BUS_PORT_NOT_BUS — Member access on non-BUS port”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Dot notation is only valid on BUS ports.</li></ul><h3 id="bus-rules-bus-signal-undefined-—-undefined-bus-signal" tabindex="-1">BUS_RULES.BUS_SIGNAL_UNDEFINED — Undefined BUS signal <a class="header-anchor" href="#bus-rules-bus-signal-undefined-—-undefined-bus-signal" aria-label="Permalink to “BUS_RULES.BUS_SIGNAL_UNDEFINED — Undefined BUS signal”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Signal does not exist in the BUS definition.</li></ul><h3 id="bus-rules-bus-signal-read-from-writable-—-read-from-writable-bus-signal" tabindex="-1">BUS_RULES.BUS_SIGNAL_READ_FROM_WRITABLE — Read from writable BUS signal <a class="header-anchor" href="#bus-rules-bus-signal-read-from-writable-—-read-from-writable-bus-signal" aria-label="Permalink to “BUS_RULES.BUS_SIGNAL_READ_FROM_WRITABLE — Read from writable BUS signal”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: This signal is write-only from the current role&#39;s perspective.</li></ul><h3 id="bus-rules-bus-signal-write-to-readable-—-write-to-readable-bus-signal" tabindex="-1">BUS_RULES.BUS_SIGNAL_WRITE_TO_READABLE — Write to readable BUS signal <a class="header-anchor" href="#bus-rules-bus-signal-write-to-readable-—-write-to-readable-bus-signal" aria-label="Permalink to “BUS_RULES.BUS_SIGNAL_WRITE_TO_READABLE — Write to readable BUS signal”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: This signal is read-only from the current role&#39;s perspective.</li></ul><h3 id="bus-rules-bus-wildcard-width-mismatch-—-wildcard-width-mismatch" tabindex="-1">BUS_RULES.BUS_WILDCARD_WIDTH_MISMATCH — Wildcard width mismatch <a class="header-anchor" href="#bus-rules-bus-wildcard-width-mismatch-—-wildcard-width-mismatch" aria-label="Permalink to “BUS_RULES.BUS_WILDCARD_WIDTH_MISMATCH — Wildcard width mismatch”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: RHS width must be 1 (broadcast) or equal to the array count (element-wise).</li></ul><h3 id="bus-rules-bus-tristate-mismatch-—-tri-state-on-non-writable-bus-signal" tabindex="-1">BUS_RULES.BUS_TRISTATE_MISMATCH — Tri-state on non-writable BUS signal <a class="header-anchor" href="#bus-rules-bus-tristate-mismatch-—-tri-state-on-non-writable-bus-signal" aria-label="Permalink to “BUS_RULES.BUS_TRISTATE_MISMATCH — Tri-state on non-writable BUS signal”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Only writable BUS signals (INOUT or OUT from this role) may be assigned <code>z</code>.</li></ul><h3 id="bus-rules-bus-bulk-bus-mismatch-—-bulk-bus-assignment-bus-mismatch" tabindex="-1">BUS_RULES.BUS_BULK_BUS_MISMATCH — Bulk BUS assignment bus mismatch <a class="header-anchor" href="#bus-rules-bus-bulk-bus-mismatch-—-bulk-bus-assignment-bus-mismatch" aria-label="Permalink to “BUS_RULES.BUS_BULK_BUS_MISMATCH — Bulk BUS assignment bus mismatch”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Both sides of a bulk BUS assignment must reference the same BUS definition.</li></ul><h3 id="bus-rules-bus-bulk-role-conflict-—-bulk-bus-assignment-role-conflict" tabindex="-1">BUS_RULES.BUS_BULK_ROLE_CONFLICT — Bulk BUS assignment role conflict <a class="header-anchor" href="#bus-rules-bus-bulk-role-conflict-—-bulk-bus-assignment-role-conflict" aria-label="Permalink to “BUS_RULES.BUS_BULK_ROLE_CONFLICT — Bulk BUS assignment role conflict”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Cannot assign between instances with the same role (SOURCE-SOURCE or TARGET-TARGET).</li></ul><hr><h2 id="clock-gen-rules" tabindex="-1">CLOCK_GEN Rules <a class="header-anchor" href="#clock-gen-rules" aria-label="Permalink to “CLOCK_GEN Rules”">​</a></h2><h3 id="clock-gen-rules-clock-gen-input-not-declared-—-input-clock-not-in-clocks" tabindex="-1">CLOCK_GEN_RULES.CLOCK_GEN_INPUT_NOT_DECLARED — Input clock not in CLOCKS <a class="header-anchor" href="#clock-gen-rules-clock-gen-input-not-declared-—-input-clock-not-in-clocks" aria-label="Permalink to “CLOCK_GEN_RULES.CLOCK_GEN_INPUT_NOT_DECLARED — Input clock not in CLOCKS”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: CLOCK_GEN input must reference a clock declared in the CLOCKS block.</li></ul><h3 id="clock-gen-rules-clock-gen-input-no-period-—-input-clock-missing-period" tabindex="-1">CLOCK_GEN_RULES.CLOCK_GEN_INPUT_NO_PERIOD — Input clock missing period <a class="header-anchor" href="#clock-gen-rules-clock-gen-input-no-period-—-input-clock-missing-period" aria-label="Permalink to “CLOCK_GEN_RULES.CLOCK_GEN_INPUT_NO_PERIOD — Input clock missing period”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: CLOCK_GEN input clock must have a period declared in CLOCKS.</li></ul><h3 id="clock-gen-rules-clock-gen-input-freq-out-of-range-—-input-frequency-out-of-range" tabindex="-1">CLOCK_GEN_RULES.CLOCK_GEN_INPUT_FREQ_OUT_OF_RANGE — Input frequency out of range <a class="header-anchor" href="#clock-gen-rules-clock-gen-input-freq-out-of-range-—-input-frequency-out-of-range" aria-label="Permalink to “CLOCK_GEN_RULES.CLOCK_GEN_INPUT_FREQ_OUT_OF_RANGE — Input frequency out of range”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Input clock frequency is outside the chip&#39;s supported range for this generator type.</li></ul><h3 id="clock-gen-rules-clock-gen-output-not-declared-—-output-clock-not-in-clocks" tabindex="-1">CLOCK_GEN_RULES.CLOCK_GEN_OUTPUT_NOT_DECLARED — Output clock not in CLOCKS <a class="header-anchor" href="#clock-gen-rules-clock-gen-output-not-declared-—-output-clock-not-in-clocks" aria-label="Permalink to “CLOCK_GEN_RULES.CLOCK_GEN_OUTPUT_NOT_DECLARED — Output clock not in CLOCKS”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: CLOCK_GEN output must reference a clock declared in the CLOCKS block.</li></ul><h3 id="clock-gen-rules-clock-gen-output-has-period-—-output-clock-has-period" tabindex="-1">CLOCK_GEN_RULES.CLOCK_GEN_OUTPUT_HAS_PERIOD — Output clock has period <a class="header-anchor" href="#clock-gen-rules-clock-gen-output-has-period-—-output-clock-has-period" aria-label="Permalink to “CLOCK_GEN_RULES.CLOCK_GEN_OUTPUT_HAS_PERIOD — Output clock has period”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: CLOCK_GEN output clocks must not have a period in CLOCKS (derived automatically).</li></ul><h3 id="clock-gen-rules-clock-gen-output-is-input-pin-—-output-clock-is-input-pin" tabindex="-1">CLOCK_GEN_RULES.CLOCK_GEN_OUTPUT_IS_INPUT_PIN — Output clock is input pin <a class="header-anchor" href="#clock-gen-rules-clock-gen-output-is-input-pin-—-output-clock-is-input-pin" aria-label="Permalink to “CLOCK_GEN_RULES.CLOCK_GEN_OUTPUT_IS_INPUT_PIN — Output clock is input pin”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: CLOCK_GEN outputs must not be declared as IN_PINS.</li></ul><h3 id="clock-gen-rules-clock-gen-multiple-drivers-—-clock-multiply-driven" tabindex="-1">CLOCK_GEN_RULES.CLOCK_GEN_MULTIPLE_DRIVERS — Clock multiply driven <a class="header-anchor" href="#clock-gen-rules-clock-gen-multiple-drivers-—-clock-multiply-driven" aria-label="Permalink to “CLOCK_GEN_RULES.CLOCK_GEN_MULTIPLE_DRIVERS — Clock multiply driven”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: A clock may only be driven by one CLOCK_GEN output.</li></ul><h3 id="clock-gen-rules-clock-gen-input-is-self-output-—-self-referencing-clock" tabindex="-1">CLOCK_GEN_RULES.CLOCK_GEN_INPUT_IS_SELF_OUTPUT — Self-referencing clock <a class="header-anchor" href="#clock-gen-rules-clock-gen-input-is-self-output-—-self-referencing-clock" aria-label="Permalink to “CLOCK_GEN_RULES.CLOCK_GEN_INPUT_IS_SELF_OUTPUT — Self-referencing clock”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: CLOCK_GEN input must not be an output of the same block.</li></ul><h3 id="clock-gen-rules-clock-gen-invalid-type-—-invalid-generator-type" tabindex="-1">CLOCK_GEN_RULES.CLOCK_GEN_INVALID_TYPE — Invalid generator type <a class="header-anchor" href="#clock-gen-rules-clock-gen-invalid-type-—-invalid-generator-type" aria-label="Permalink to “CLOCK_GEN_RULES.CLOCK_GEN_INVALID_TYPE — Invalid generator type”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Generator type must be PLL, DLL, CLKDIV, or OSC.</li></ul><h3 id="clock-gen-rules-clock-gen-missing-input-—-missing-in-clock" tabindex="-1">CLOCK_GEN_RULES.CLOCK_GEN_MISSING_INPUT — Missing IN clock <a class="header-anchor" href="#clock-gen-rules-clock-gen-missing-input-—-missing-in-clock" aria-label="Permalink to “CLOCK_GEN_RULES.CLOCK_GEN_MISSING_INPUT — Missing IN clock”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Generator must declare an IN clock (except OSC which has no external input).</li></ul><h3 id="clock-gen-rules-clock-gen-missing-output-—-missing-out-clock" tabindex="-1">CLOCK_GEN_RULES.CLOCK_GEN_MISSING_OUTPUT — Missing OUT clock <a class="header-anchor" href="#clock-gen-rules-clock-gen-missing-output-—-missing-out-clock" aria-label="Permalink to “CLOCK_GEN_RULES.CLOCK_GEN_MISSING_OUTPUT — Missing OUT clock”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Generator must declare at least one OUT clock.</li></ul><h3 id="clock-gen-rules-clock-gen-param-out-of-range-—-config-parameter-out-of-range" tabindex="-1">CLOCK_GEN_RULES.CLOCK_GEN_PARAM_OUT_OF_RANGE — CONFIG parameter out of range <a class="header-anchor" href="#clock-gen-rules-clock-gen-param-out-of-range-—-config-parameter-out-of-range" aria-label="Permalink to “CLOCK_GEN_RULES.CLOCK_GEN_PARAM_OUT_OF_RANGE — CONFIG parameter out of range”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Parameter value is outside the chip&#39;s valid range.</li></ul><h3 id="clock-gen-rules-clock-gen-derived-out-of-range-—-derived-frequency-out-of-range" tabindex="-1">CLOCK_GEN_RULES.CLOCK_GEN_DERIVED_OUT_OF_RANGE — Derived frequency out of range <a class="header-anchor" href="#clock-gen-rules-clock-gen-derived-out-of-range-—-derived-frequency-out-of-range" aria-label="Permalink to “CLOCK_GEN_RULES.CLOCK_GEN_DERIVED_OUT_OF_RANGE — Derived frequency out of range”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Computed VCO or output frequency is outside the chip&#39;s valid range. Adjust CONFIG parameters.</li></ul><hr><h2 id="path-security" tabindex="-1">Path Security <a class="header-anchor" href="#path-security" aria-label="Permalink to “Path Security”">​</a></h2><h3 id="path-security-path-absolute-forbidden-—-absolute-path-used" tabindex="-1">PATH_SECURITY.PATH_ABSOLUTE_FORBIDDEN — Absolute path used <a class="header-anchor" href="#path-security-path-absolute-forbidden-—-absolute-path-used" aria-label="Permalink to “PATH_SECURITY.PATH_ABSOLUTE_FORBIDDEN — Absolute path used”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: An <code>@import</code> or <code>@file()</code> path begins with <code>/</code> (or drive letter on Windows).</li><li>Fix: Use relative paths or pass <code>--allow-absolute-paths</code>.</li></ul><h3 id="path-security-path-traversal-forbidden-—-directory-traversal" tabindex="-1">PATH_SECURITY.PATH_TRAVERSAL_FORBIDDEN — Directory traversal <a class="header-anchor" href="#path-security-path-traversal-forbidden-—-directory-traversal" aria-label="Permalink to “PATH_SECURITY.PATH_TRAVERSAL_FORBIDDEN — Directory traversal”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Path contains <code>..</code> component.</li><li>Fix: Remove <code>..</code> from path or pass <code>--allow-traversal</code>.</li></ul><h3 id="path-security-path-outside-sandbox-—-path-outside-sandbox" tabindex="-1">PATH_SECURITY.PATH_OUTSIDE_SANDBOX — Path outside sandbox <a class="header-anchor" href="#path-security-path-outside-sandbox-—-path-outside-sandbox" aria-label="Permalink to “PATH_SECURITY.PATH_OUTSIDE_SANDBOX — Path outside sandbox”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: Resolved canonical path does not start with any permitted sandbox root.</li><li>Fix: Use <code>--sandbox-root=&lt;dir&gt;</code> to add additional permitted directories.</li></ul><h3 id="path-security-path-symlink-escape-—-symlink-escapes-sandbox" tabindex="-1">PATH_SECURITY.PATH_SYMLINK_ESCAPE — Symlink escapes sandbox <a class="header-anchor" href="#path-security-path-symlink-escape-—-symlink-escapes-sandbox" aria-label="Permalink to “PATH_SECURITY.PATH_SYMLINK_ESCAPE — Symlink escapes sandbox”">​</a></h3><ul><li>Severity: ERROR</li><li>Cause: A symbolic link inside the sandbox resolves to a target outside the sandbox.</li><li>Fix: Remove the symlink or add the target directory to <code>--sandbox-root</code>.</li></ul><hr><h2 id="lit-intrinsic-rules" tabindex="-1">lit() Intrinsic Rules <a class="header-anchor" href="#lit-intrinsic-rules" aria-label="Permalink to “lit() Intrinsic Rules”">​</a></h2><h3 id="functions-and-lit-lit-width-invalid-—-lit-width-invalid" tabindex="-1">FUNCTIONS_AND_LIT.LIT_WIDTH_INVALID — lit() width invalid <a class="header-anchor" href="#functions-and-lit-lit-width-invalid-—-lit-width-invalid" aria-label="Permalink to “FUNCTIONS_AND_LIT.LIT_WIDTH_INVALID — lit() width invalid”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Width must be a positive integer constant expression.</li></ul><h3 id="functions-and-lit-lit-value-invalid-—-lit-value-invalid" tabindex="-1">FUNCTIONS_AND_LIT.LIT_VALUE_INVALID — lit() value invalid <a class="header-anchor" href="#functions-and-lit-lit-value-invalid-—-lit-value-invalid" aria-label="Permalink to “FUNCTIONS_AND_LIT.LIT_VALUE_INVALID — lit() value invalid”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Value must be a nonnegative integer constant expression.</li></ul><h3 id="functions-and-lit-lit-value-overflow-—-lit-value-overflows-width" tabindex="-1">FUNCTIONS_AND_LIT.LIT_VALUE_OVERFLOW — lit() value overflows width <a class="header-anchor" href="#functions-and-lit-lit-value-overflow-—-lit-value-overflows-width" aria-label="Permalink to “FUNCTIONS_AND_LIT.LIT_VALUE_OVERFLOW — lit() value overflows width”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Value exceeds the declared width.</li></ul><h3 id="functions-and-lit-lit-invalid-context-—-lit-in-compile-time-context" tabindex="-1">FUNCTIONS_AND_LIT.LIT_INVALID_CONTEXT — lit() in compile-time context <a class="header-anchor" href="#functions-and-lit-lit-invalid-context-—-lit-in-compile-time-context" aria-label="Permalink to “FUNCTIONS_AND_LIT.LIT_INVALID_CONTEXT — lit() in compile-time context”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: lit() produces a runtime literal; it is not valid where a compile-time integer constant is required.</li></ul><hr><h2 id="testbench-rules" tabindex="-1">Testbench Rules <a class="header-anchor" href="#testbench-rules" aria-label="Permalink to “Testbench Rules”">​</a></h2><h3 id="testbench-tb-module-not-found-—-module-not-found" tabindex="-1">TESTBENCH.TB_MODULE_NOT_FOUND — Module not found <a class="header-anchor" href="#testbench-tb-module-not-found-—-module-not-found" aria-label="Permalink to “TESTBENCH.TB_MODULE_NOT_FOUND — Module not found”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: @testbench module name must refer to a module in scope.</li></ul><h3 id="testbench-tb-port-not-connected-—-port-not-connected" tabindex="-1">TESTBENCH.TB_PORT_NOT_CONNECTED — Port not connected <a class="header-anchor" href="#testbench-tb-port-not-connected-—-port-not-connected" aria-label="Permalink to “TESTBENCH.TB_PORT_NOT_CONNECTED — Port not connected”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: All module ports must be connected in @new.</li></ul><h3 id="testbench-tb-port-width-mismatch-—-port-width-mismatch" tabindex="-1">TESTBENCH.TB_PORT_WIDTH_MISMATCH — Port width mismatch <a class="header-anchor" href="#testbench-tb-port-width-mismatch-—-port-width-mismatch" aria-label="Permalink to “TESTBENCH.TB_PORT_WIDTH_MISMATCH — Port width mismatch”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Port width must match module declared width.</li></ul><h3 id="testbench-tb-new-rhs-invalid-—-invalid-new-rhs" tabindex="-1">TESTBENCH.TB_NEW_RHS_INVALID — Invalid @new RHS <a class="header-anchor" href="#testbench-tb-new-rhs-invalid-—-invalid-new-rhs" aria-label="Permalink to “TESTBENCH.TB_NEW_RHS_INVALID — Invalid @new RHS”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: @new RHS must be a testbench CLOCK or WIRE.</li></ul><h3 id="testbench-tb-setup-position-—-setup-position-invalid" tabindex="-1">TESTBENCH.TB_SETUP_POSITION — @setup position invalid <a class="header-anchor" href="#testbench-tb-setup-position-—-setup-position-invalid" aria-label="Permalink to “TESTBENCH.TB_SETUP_POSITION — @setup position invalid”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: @setup must appear exactly once per TEST, after @new, before other directives.</li></ul><h3 id="testbench-tb-clock-not-declared-—-clock-not-declared" tabindex="-1">TESTBENCH.TB_CLOCK_NOT_DECLARED — Clock not declared <a class="header-anchor" href="#testbench-tb-clock-not-declared-—-clock-not-declared" aria-label="Permalink to “TESTBENCH.TB_CLOCK_NOT_DECLARED — Clock not declared”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: @clock clock identifier must refer to a declared CLOCK.</li></ul><h3 id="testbench-tb-clock-cycle-not-positive-—-non-positive-cycle-count" tabindex="-1">TESTBENCH.TB_CLOCK_CYCLE_NOT_POSITIVE — Non-positive cycle count <a class="header-anchor" href="#testbench-tb-clock-cycle-not-positive-—-non-positive-cycle-count" aria-label="Permalink to “TESTBENCH.TB_CLOCK_CYCLE_NOT_POSITIVE — Non-positive cycle count”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: @clock cycle count must be a positive integer.</li></ul><h3 id="testbench-tb-update-not-wire-—-update-targets-non-wire" tabindex="-1">TESTBENCH.TB_UPDATE_NOT_WIRE — @update targets non-wire <a class="header-anchor" href="#testbench-tb-update-not-wire-—-update-targets-non-wire" aria-label="Permalink to “TESTBENCH.TB_UPDATE_NOT_WIRE — @update targets non-wire”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: @update may only assign testbench WIRE identifiers.</li></ul><h3 id="testbench-tb-update-clock-assign-—-update-assigns-clock" tabindex="-1">TESTBENCH.TB_UPDATE_CLOCK_ASSIGN — @update assigns clock <a class="header-anchor" href="#testbench-tb-update-clock-assign-—-update-assigns-clock" aria-label="Permalink to “TESTBENCH.TB_UPDATE_CLOCK_ASSIGN — @update assigns clock”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: @update may not assign clock signals.</li></ul><h3 id="testbench-tb-expect-width-mismatch-—-expect-width-mismatch" tabindex="-1">TESTBENCH.TB_EXPECT_WIDTH_MISMATCH — @expect width mismatch <a class="header-anchor" href="#testbench-tb-expect-width-mismatch-—-expect-width-mismatch" aria-label="Permalink to “TESTBENCH.TB_EXPECT_WIDTH_MISMATCH — @expect width mismatch”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: @expect value width must match signal width.</li></ul><h3 id="testbench-tb-no-test-blocks-—-no-test-blocks" tabindex="-1">TESTBENCH.TB_NO_TEST_BLOCKS — No TEST blocks <a class="header-anchor" href="#testbench-tb-no-test-blocks-—-no-test-blocks" aria-label="Permalink to “TESTBENCH.TB_NO_TEST_BLOCKS — No TEST blocks”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: @testbench must contain at least one TEST block.</li></ul><h3 id="testbench-tb-multiple-new-—-multiple-new" tabindex="-1">TESTBENCH.TB_MULTIPLE_NEW — Multiple @new <a class="header-anchor" href="#testbench-tb-multiple-new-—-multiple-new" aria-label="Permalink to “TESTBENCH.TB_MULTIPLE_NEW — Multiple @new”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: Each TEST must contain exactly one @new instantiation.</li></ul><h3 id="testbench-tb-project-mixed-—-mixed-project-and-testbench" tabindex="-1">TESTBENCH.TB_PROJECT_MIXED — Mixed @project and @testbench <a class="header-anchor" href="#testbench-tb-project-mixed-—-mixed-project-and-testbench" aria-label="Permalink to “TESTBENCH.TB_PROJECT_MIXED — Mixed @project and @testbench”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: A file may not contain both @project and @testbench.</li></ul><hr><h2 id="simulation-rules" tabindex="-1">Simulation Rules <a class="header-anchor" href="#simulation-rules" aria-label="Permalink to “Simulation Rules”">​</a></h2><h3 id="simulation-sim-project-mixed-—-mixed-project-and-simulation" tabindex="-1">SIMULATION.SIM_PROJECT_MIXED — Mixed @project and @simulation <a class="header-anchor" href="#simulation-sim-project-mixed-—-mixed-project-and-simulation" aria-label="Permalink to “SIMULATION.SIM_PROJECT_MIXED — Mixed @project and @simulation”">​</a></h3><ul><li>Severity: ERROR</li><li>Fix: A file may not contain both @project and @simulation.</li></ul>',566)])])}const E=i(n,[["render",r]]);export{_ as __pageData,E as default};
